// 驾考科目一 2026新规题库 Part 3 (291-500题)
var Q = Q || [];
Q.push(
// ═══════════════════════════════════════════════════════════════
// 七、高速公路 (highway) — 35题 (291-325)
// ═══════════════════════════════════════════════════════════════
{id:291,cat:"highway",type:"choice",q:"高速公路最高限速是多少？",opts:["100km/h","110km/h","120km/h","130km/h"],ans:2,exp:"根据《道路交通安全法实施条例》，高速公路最高限速为120km/h。小型载客汽车在最左侧车道最高120km/h，其他机动车最高100km/h，摩托车最高80km/h。",tip:"口诀：高速封顶120（小车最左道），大车最高100，摩托最高80。"},
{id:292,cat:"highway",type:"choice",q:"高速公路最低限速是多少？",opts:["40km/h","50km/h","60km/h","80km/h"],ans:2,exp:"高速公路最低限速为60km/h。设计最高时速低于70km/h的机动车不得进入高速公路。低于最低限速行驶记3分。",tip:"口诀：高速最低60码，低于最低限速记3分。太慢也是错。"},
{id:293,cat:"highway",type:"choice",q:"在高速公路上车速超过100km/h时，应与前车保持多少米以上的安全距离？",opts:["50米","80米","100米","150米"],ans:2,exp:"高速车速>100km/h时，安全距离≥100米；车速<100km/h时，≥50米。可利用路面上的车距确认标线（每50米一组）确认距离。",tip:"口诀：高速跟车——过100码保持100米，不到100码至少50米。车距确认线帮你量。"},
{id:294,cat:"highway",type:"choice",q:"在高速公路上，除什么情况外不得在应急车道行驶或停车？",opts:["车辆故障或紧急情况","想休息一下","接打电话","查看导航"],ans:0,exp:"应急车道仅供车辆故障、事故等紧急情况时使用。非紧急占用一次记9分（2026新规由6分加重为9分）。",tip:"口诀：应急车道=生命通道，非急占用记9分。不是休息区！"},
{id:295,cat:"highway",type:"judgment",q:"从匝道驶入高速公路时，可以直接并入最左侧快车道。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"匝道进高速的正确做法：在加速车道内提至60km/h以上→观察左后视镜确认安全→打左转向灯→先并入右侧行车道→再根据情况变至更左车道。禁止跨越多条车道直接并入最左快车道。",tip:"口诀：匝道进高速=加速车道提速→先并入最右车道→再逐步变到目标车道。不能一步跨到最左边。"},
{id:296,cat:"highway",type:"choice",q:"机动车驶离高速公路时，应当提前开启什么灯？",opts:["危险报警闪光灯","右转向灯","左转向灯","前照灯"],ans:1,exp:"驶离高速公路前应提前开右转向灯→变至最右车道→驶入减速车道→经匝道驶离。错过出口继续前行至下一出口，严禁倒车。",tip:"口诀：出高速=打右灯→变最右道→减速车道→匝道。错过出口继续走。"},
{id:297,cat:"highway",type:"choice",q:"在高速公路上错过出口，正确的做法是？",opts:["立即停车倒回去","继续行驶至下一个出口","掉头逆行","在应急车道上停车商量"],ans:1,exp:"错过出口=继续行驶到下一出口。高速倒车/逆行/掉头一次记12分。前方多走几公里好过满分清零+事故风险。",tip:"口诀：错过出口继续走，下个出口再折返。倒车逆行12分，多花时间省分数和命。"},
{id:298,cat:"highway",type:"choice",q:"车辆在高速公路发生故障，哪项做法是错误的？",opts:["开启双闪","在来车方向150米外设警告标志","将车上人员转移到安全地带","让乘客在车内等待"],ans:3,exp:"高速故障后人员必须撤离到护栏外安全地带，严禁留在车内或车旁。二次事故是高速公路上最致命的风险。",tip:"口诀：高速故障=人先撤到护栏外（最关键）→150米放警示牌→报警。人不能待在车道和车里。"},
{id:299,cat:"highway",type:"choice",q:"高速公路同向有3条车道的，左侧车道最低车速为多少？",opts:["60km/h","80km/h","100km/h","110km/h"],ans:3,exp:"同向3车道：左侧车道最低110km/h、中间车道最低90km/h、右侧车道最低60km/h。同向2车道：左100km/h、右60km/h。",tip:"口诀：3车道——左110中90右60；2车道——左100右60。车道越多，快慢分得越细。"},
{id:300,cat:"highway",type:"judgment",q:"在同向有3条以上车道的高速公路上，大型货车和大客车应当在最右侧车道行驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"大车限速较低，原则上应在最右侧车道行驶。超车时可借用相邻车道，超车完成后应返回右侧车道。",tip:"口诀：大车靠右走——超车借左道，超完回右道。不长期占用快车道。"},
{id:301,cat:"highway",type:"judgment",q:"在高速公路上，除遇障碍或发生故障等必须停车的情况外，不准随意停车或停车上下人员或装卸货物。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路上禁止随意停车、上下人员或装卸货物。需要停车休息或加油应进入服务区。违法停车记9分。",tip:"口诀：高速上别停车——休息去服务区，加油去服务区，上厕所也去服务区。"},
{id:302,cat:"highway",type:"choice",q:"车辆在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件，能见度低于200米时，最高车速不得超过多少？",opts:["80km/h","60km/h","40km/h","20km/h"],ans:1,exp:"能见度<200米→最高60km/h→与前车保持100米以上距离。开启雾灯、近光灯、示廓灯和前后位灯。",tip:"口诀：能见度200米→限速60→间距100。能见度越低，速度和间距越要收紧。"},
{id:303,cat:"highway",type:"choice",q:"高速公路能见度低于100米时，最高车速不得超过多少？",opts:["60km/h","50km/h","40km/h","20km/h"],ans:2,exp:"能见度<100米→最高40km/h→与前车保持50米以上距离。同时开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯。",tip:"口诀：能见度100米→限速40→间距50→开所有灯（远光除外）。100-40-50数字递减。"},
{id:304,cat:"highway",type:"choice",q:"高速公路能见度低于50米时，应如何处理？",opts:["以不超过20km/h的速度行驶并尽快从最近出口驶离","保持40km/h行驶","靠边停车等待","继续以正常速度行驶"],ans:0,exp:"能见度<50米→最高20km/h→开启所有灯光→尽快从最近出口驶离高速或进入服务区。此时继续行驶极其危险。",tip:"口诀：能见度50米→限速20→赶紧离开高速！「50-20-离」=大雾天的保命口诀。"},
{id:305,cat:"highway",type:"judgment",q:"在高速公路上行驶时，可以在匝道、加速车道或者减速车道上超车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"匝道、加速车道和减速车道上严禁超车。这些路段设计用于进出高速、车速变化，超车极易引发事故。",tip:"口诀：匝道/加速/减速车道=禁止超车。进出口是危险区，不是超车道。"},
{id:306,cat:"highway",type:"choice",q:"进入高速公路隧道前50米左右，应如何操作？",opts:["加速通过","开启近光灯，减速行驶","鸣喇叭","关闭所有车灯"],ans:1,exp:"进隧道前应开启近光灯（提前适应暗光环境），减速至限速范围内，保持安全车距。隧道内外的亮度差异可能导致短暂的「黑洞效应」和「白洞效应」。",tip:"口诀：隧道前50米=开近光+减速。进隧道一瞬间眼睛需要适应，慢就对了。"},
{id:307,cat:"highway",type:"choice",q:"车辆在高速公路匝道上行驶时，最高速度不得超过多少？",opts:["20km/h","30km/h","40km/h","60km/h"],ans:2,exp:"高速公路匝道限速一般为40km/h（具体以匝道限速标志为准）。匝道转弯半径小、车道窄，车速过快极易失控。",tip:"口诀：匝道限速40码（看标志为主）。匝道=弯急路窄，慢进慢出。"},
{id:308,cat:"highway",type:"judgment",q:"在高速公路上驾驶机动车，如果感觉疲劳，可以在应急车道上停车休息片刻。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"应急车道不是休息区！疲劳时应驶入最近的服务区或从最近出口驶离高速休息。在应急车道无故停车记9分。",tip:"口诀：高速累了去服务区，别停应急道。应急车道=紧急专用，困了不算紧急。"},
{id:309,cat:"highway",type:"choice",q:"在高速公路上，以下哪项关于安全带的使用说法正确？",opts:["只有驾驶人需要系","只有前排需要系","所有乘车人（含后排）都应系安全带","高速公路上可以不系"],ans:2,exp:"高速公路所有乘车人（含后排）都必须系安全带。高速碰撞时，未系安全带的后排乘客会以极高的速度撞向前排和挡风玻璃，伤害自己和他人。",tip:"口诀：高速全员系安全带。后排不系=碰撞时变成炮弹砸向前排。"},
{id:310,cat:"highway",type:"choice",q:"车辆在高速公路上以100km/h的速度行驶时，从发现危险到完全停车，制动距离大约是多少？",opts:["30米左右","50米左右","100米左右","150米以上"],ans:3,exp:"100km/h时的总停车距离（反应距离+制动距离）在干燥路面约100-150米，湿滑路面更长。反应时间（从看到危险到踩下刹车）约1.5秒，这段时间车辆已前进约42米。",tip:"口诀：100码速度=刹车距离150米以上。这就是为什么跟车要保持100米——给你反应+刹车的时间。"},
{id:311,cat:"highway",type:"judgment",q:"在高速公路上，大型车辆在正常情况下可以在左侧快车道长时间行驶。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"大型车辆（最高限速100km/h）应在右侧车道行驶，超车时可借用左侧车道，完成超车后应立即驶回右侧车道。不得长时间占用左侧快车道。",tip:"口诀：大车不许长期占快车道。超车借道，超完让道。"},
{id:312,cat:"highway",type:"choice",q:"高速公路上的车距确认标线（白色V形或长方形标线）的作用是什么？",opts:["减速标线","供驾驶人确认与前车距离的参照","人行横道预告","车道分界线"],ans:1,exp:"车距确认标线通常每50米设置一组，配合路侧的「0m」「50m」「100m」标志，供驾驶人直观确认与前车的安全距离是否符合要求。",tip:"口诀：高速公路上的V形白标线=车距尺，每50米一组，帮你测跟车距离。"},
{id:313,cat:"highway",type:"judgment",q:"在高速公路上行驶，驾驶人感觉车辆轻微跑偏，可以在应急车道上停车检查。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"非紧急情况不得在应急车道停车。轻微跑偏不属于「车辆发生故障无法行驶」的紧急情况。应到最近服务区或驶离高速后检查。",tip:"口诀：车还能开就开到服务区再检查。应急车道不是检修车道。"},
{id:314,cat:"highway",type:"choice",q:"高速公路路肩（硬路肩）的主要作用是什么？",opts:["超车道","提供给故障车辆紧急停靠和紧急救援车辆通行","行车道","休息区"],ans:1,exp:"硬路肩=应急停车+救援通道。正常行驶车辆严禁占用。路肩宽度一般2.5-3.5米，供故障车辆临时停靠。",tip:"口诀：硬路肩=应急用，平时不能在上面走。故障车停+救援车走。"},
{id:315,cat:"highway",type:"choice",q:"在高速公路行车时，前方突然出现障碍物，正确的处置方法是？",opts:["急打方向绕开","紧急制动","紧握方向盘，减速，在安全前提下小角度避让","加速冲过去"],ans:2,exp:"高速遇障碍物=握紧方向+减速+小角度避让。猛打方向极易导致车辆失控侧翻，急刹可能导致追尾。",tip:"口诀：高速遇障碍→握紧方向→减速→小角度绕。打死方向=翻车。"},
{id:316,cat:"highway",type:"judgment",q:"车辆在高速公路上不得试车或学习驾驶机动车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路上严禁试车和学习驾驶。实习期驾驶人上高速需有3年以上驾龄的驾驶人陪同。",tip:"口诀：高速不是练车场——禁止试车+禁止学车+新手需老司机陪。"},
{id:317,cat:"highway",type:"choice",q:"高速公路上的变速车道包括哪两种？",opts:["快速车道和慢速车道","加速车道和减速车道","超车道和行车道","应急车道和爬坡车道"],ans:1,exp:"变速车道=加速车道（匝道进入主线前提速用）+减速车道（驶离主线进入匝道前减速用）。两种车道长度通常在150-300米。",tip:"口诀：变速车道两兄弟——加速道（进来时提速）+减速道（出去时减速）。"},
{id:318,cat:"highway",type:"judgment",q:"车辆在高速公路行驶中因故障需要救援时，应由高速公路经营管理单位组织的专业救援车辆拖拽至最近出口或服务区。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路上车辆故障应由高速公路专业救援车辆（清障车）进行拖拽，驾驶人不得自行拦截过往车辆拖拽。故障车应拖至最近出口或服务区。",tip:"口诀：高速拖车=专业救援队（非私人拖车）。打12122叫高速救援。"},
{id:319,cat:"highway",type:"choice",q:"关于高速公路服务区的使用，下列说法正确的是？",opts:["长时间占用服务区停车位休息","在服务区入口加速车道停车","按服务区指示标志行驶和停放，停车休息时间不宜过长","在服务区内高速行驶"],ans:2,exp:"服务区应按指示行驶和停放，不得长时间占用停车位（影响他人使用）。进出服务区应减速，注意行人和其他车辆。",tip:"口诀：服务区=休息+加油+如厕。停好车，别占位太久，进出要慢。"},
{id:320,cat:"highway",type:"choice",q:"在没有限速标志的高速公路上，大型客车和货车的最高限速是多少？",opts:["80km/h","90km/h","100km/h","110km/h"],ans:2,exp:"高速公路无特别限速标志时：小型载客汽车最高120km/h、其他机动车（含大型客车、货车）最高100km/h、摩托车最高80km/h。",tip:"口诀：无标志高速限速——小车120、大车/客车100、摩托80。"},
{id:321,cat:"highway",type:"judgment",q:"驾驶机动车在高速公路上行驶时，可以在行车道内直接停车查看导航。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"行车道上严禁停车！需设置导航应在出发前完成，或驶入服务区后停车操作。高速公路随意停车记9分。",tip:"口诀：高速停车看导航=9分。出发前设好，需要改进去服务区再停。"},
{id:322,cat:"highway",type:"choice",q:"高速公路上的爬坡车道设置目的是什么？",opts:["给超车用","供速度降低的大型车辆使用，减少对其他车辆的影响","给摩托车专用","应急停车用"],ans:1,exp:"爬坡车道设于长陡上坡路段，供上坡时速度显著降低的大型车辆使用，使其驶离主线车道，保障其他车辆正常通行。",tip:"口诀：爬坡车道=大车慢车专用道（上坡路段）。大车上坡慢，去右边专用道。"},
{id:323,cat:"highway",type:"judgment",q:"高速公路正常行驶中，车辆在行车道内突发故障不能行驶的，应当在确保安全的情况下将车移至应急车道或路肩上。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"车辆故障时应在确保安全的前提下，利用剩余动力或惯性将车移至应急车道或路肩，尽量避免停在行车道上。确实无法移动的应开启双闪、设警示牌、人员撤离、报警。",tip:"口诀：高速故障→尽量挪到应急车道→开双闪→150米放牌→人撤离→报警。"},
{id:324,cat:"highway",type:"choice",q:"关于高速公路夜间行驶，下列哪项是正确的？",opts:["一直使用远光灯","照明良好路段应使用近光灯，无照明且无来车时可使用远光灯","完全不用开灯","只开示廓灯即可"],ans:1,exp:"高速夜间行驶灯光使用原则与普通道路相同：有照明=近光，无照明+无来车=远光，会车跟车=近光。高速远光灯使用不当同样危险。",tip:"口诀：高速夜间灯光=同普通路原则。有灯用近光，无灯用远光，会车改近光。"},
{id:325,cat:"highway",type:"judgment",q:"在高速公路上，同方向有2条车道的，左侧车道为快车道，最低车速100km/h；右侧车道为行车道，最低车速60km/h。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"同向2车道高速：左道最低100km/h、右道最低60km/h。同向3车道：左110、中90、右60。同向4车道及以上以此类推。",tip:"口诀：2车道左100右60。没记错，左侧永远是快速道，右侧永远是慢速道。"},

// ═══════════════════════════════════════════════════════════════
// 八、恶劣天气/复杂道路 (weather) — 35题 (326-360)
// ═══════════════════════════════════════════════════════════════
{id:326,cat:"weather",type:"choice",q:"雨天路面湿滑，车轮与路面的附着力会如何变化？",opts:["增大","减小","不变","时大时小"],ans:1,exp:"雨天路面湿滑，轮胎与路面之间形成水膜，附着力显著减小（约为干燥路面的1/2到2/3）。制动距离延长1.5-2倍，容易发生侧滑和水滑现象。",tip:"口诀：雨天附着力↓，刹车距离↑1.5-2倍。慢+远+稳。"},
{id:327,cat:"weather",type:"choice",q:"能见度低于200米时，高速公路上最高车速和跟车距离分别是多少？",opts:["80km/h，150米","60km/h，100米","40km/h，50米","20km/h，尽快驶离"],ans:1,exp:"能见度<200米→限速60km/h→间距≥100米。开启雾灯、近光灯、示廓灯和前后位灯。",tip:"口诀：200-60-100（能见度→限速→间距）。三个数字绑一起记。"},
{id:328,cat:"weather",type:"choice",q:"能见度低于100米时，高速公路上最高车速和跟车距离分别是多少？",opts:["60km/h，100米","40km/h，50米","30km/h，30米","20km/h，尽快驶离"],ans:1,exp:"能见度<100米→限速40km/h→间距≥50米。开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯。",tip:"口诀：100-40-50。能见度100米，限速变40，间距缩50。"},
{id:329,cat:"weather",type:"choice",q:"能见度低于50米时，高速公路上应如何处理？",opts:["以20km/h行驶并尽快驶离高速","保持40km/h行驶","靠应急车道停车等待","正常行驶但开双闪"],ans:0,exp:"能见度<50米→限速20km/h→开启所有灯光→尽快从最近出口驶离高速或进入服务区。能见度不足50米已属于极端危险天气，继续行驶风险极大。",tip:"口诀：50-20-离（能见度50→20码→离开高速）。大雾天保命口诀。"},
{id:330,cat:"weather",type:"choice",q:"在冰雪路面上行驶时，正确的做法是什么？",opts:["急踩刹车","急打方向","保持低速匀速行驶，避免急加速急刹车急打方向","空挡滑行"],ans:2,exp:"冰雪路面附着力极低（约为干燥路面的1/4），应保持低速匀速行驶，三不急——不急加速、不急刹车、不急打方向。跟车距离应为平时的3-4倍。",tip:"口诀：冰雪路=「三不急」+车距3-4倍。像端着满满一杯水开车，一滴不洒。"},
{id:331,cat:"weather",type:"choice",q:"雾天行车时，应当开启什么灯？",opts:["远光灯","雾灯和近光灯","只开近光灯","关掉所有灯"],ans:1,exp:"雾天=雾灯+近光灯。严禁使用远光灯——远光会被雾气中的水滴反射，形成白茫茫的「光墙」，反而什么都看不见。能见度极低时加开双闪。",tip:"口诀：雾天=雾灯+近光。远光灯是雾天最大杀手——打远光=白茫茫一片全看不见。"},
{id:332,cat:"weather",type:"judgment",q:"在山区道路转弯时，应做到减速、鸣笛、靠右行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"山路转弯三要素=减速+鸣喇叭（或夜间闪灯）+靠右行驶。可以有效预防与对向来车发生碰撞。",tip:"口诀：山路转弯三部曲——减速→鸣笛（或闪灯）→靠右。各唱各的调，互不撞。"},
{id:333,cat:"weather",type:"choice",q:"车辆在冰雪路面发生侧滑时，正确的做法是什么？",opts:["猛踩刹车","向后轮侧滑的方向转向","向前轮侧滑的方向转向","松开油门，向车尾甩出的方向缓慢修正方向"],ans:3,exp:"冰雪路面侧滑=松油门减速（不踩刹车）+向车尾甩出的同一方向轻微转动方向盘修正。牢记「车尾往哪甩，方向往哪打」。急刹或反打方向会加剧失控。",tip:"口诀：冰雪侧滑→松油门+方向顺着车尾走（车尾往右甩，方向往右轻打）。别反打！"},
{id:334,cat:"weather",type:"choice",q:"雨天车辆在泥泞路段发生车轮打滑空转时，应如何处理？",opts:["加大油门冲过去","挂低速挡，轻踩油门，适当左右转动方向盘","紧急制动停车","挂倒挡退出"],ans:1,exp:"泥泞路段打滑空转=挂低速挡+轻踩油门+适当左右打方向增加抓地力。大油门只会让车轮越陷越深。如果车辆陷入泥中无法驶出，可垫入砂石、木板增加摩擦力。",tip:"口诀：泥泞打滑=低挡+轻油+左右摇摆方向找抓地力。猛踩油门=越陷越深。"},
{id:335,cat:"weather",type:"judgment",q:"大风天气行车中，遇到横风使车辆发生横向偏移时，应迅速猛打方向盘进行修正。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"横风偏移=双手紧握方向盘+轻微修正+适当减速。迅速猛打方向极易导致失控侧翻。桥梁、隧道口、山口等位置的横风尤其危险，应提前减速。",tip:"口诀：横风来了→握紧方向→轻打微调→慢。猛打方向=翻车。过桥/隧道口注意横风标志。"},
{id:336,cat:"weather",type:"choice",q:"在泥泞路段行车，车轮最容易发生什么情况？",opts:["爆胎","侧滑和原地打滑","制动更灵敏","转向更轻松"],ans:1,exp:"泥泞路段附着力极低，车轮容易发生侧滑（横向滑动）和原地打滑（空转）。应用低速挡匀速通过，避免中途停车和换挡。",tip:"口诀：泥泞路=滑溜溜。低挡匀速一次性通过，中途别停别换挡。"},
{id:337,cat:"weather",type:"choice",q:"夜间在山区弯道行驶时，应如何使用灯光？",opts:["一直用远光","交替使用远近光灯，接近弯道时减速靠右鸣喇叭","关闭灯光","只用示廓灯"],ans:1,exp:"夜间山路弯道=交替远近光（闪灯）提醒对向来车+减速靠右+鸣喇叭。多种方式向看不见的对方示意你的存在。",tip:"口诀：夜山路弯道=闪灯+鸣笛+减速靠右。三重信号保安全。"},
{id:338,cat:"weather",type:"judgment",q:"雨天超车时，应加速尽快完成超车，缩短与被超车辆的并行时间。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"雨天路滑、视野差，应尽量避免超车。确需超车时，应选择宽阔平坦路段，提前打灯，平稳完成超车。加速猛冲在湿滑路面极易打滑失控。",tip:"口诀：雨天尽量不超车。非得超=选宽平路段+平稳操作。雨天猛加速=找打滑。"},
{id:339,cat:"weather",type:"choice",q:"暴雨天气行车，雨刮器开到最大档仍看不清前方时，应如何做？",opts:["继续行驶","减速并开启双闪，尽快选择安全地点停车等待雨势减小","加速通过暴雨区","靠边但不开启任何灯光"],ans:1,exp:"雨刮器无法满足视野需求=极度危险。应减速开启双闪，尽快找安全地点（服务区、高速出口、路边安全开阔地带）停车等待。不要在行车道减速慢行（容易被追尾）。",tip:"口诀：暴雨看不清=开双闪→找安全地停→等雨小。别慢吞吞开在路上当靶子。"},
{id:340,cat:"weather",type:"choice",q:"在积水路段行车时，以下做法错误的是？",opts:["挂低速挡匀速通过","中途不停车、不换挡","加速冲过积水区","涉水后轻踩刹车排干制动器水分"],ans:2,exp:"加速冲过积水区=极其错误！高速冲水会使水花溅入发动机进气口（导致发动机进水损坏）、失去抓地力（水滑现象）、溅起的水浪影响其他车辆。正确做法是低挡匀速缓慢通过。",tip:"口诀：积水=低挡慢过，绝不加速冲。快过水=毁发动机+失控+溅别人一身。"},
{id:341,cat:"weather",type:"judgment",q:"涉水行车时，如水位超过排气管口，可能造成发动机熄火。此时应尝试重新启动发动机。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"涉水熄火后严禁重新启动！水可能已通过进气管进入气缸，再次启动会造成发动机「顶缸」（水不可压缩，活塞上行撞弯连杆），导致发动机报废。正确做法：不要启动→拨打救援电话→等待专业人员处理。",tip:"口诀：涉水熄火=千万别再打火！一打火发动机报废。等救援来拖走。"},
{id:342,cat:"weather",type:"choice",q:"在结冰的道路上行驶，制动距离大约是干燥路面的多少倍？",opts:["1.5倍","2-3倍","3-5倍","10倍左右"],ans:2,exp:"冰面附着力极低（约为干燥路面的1/10到1/4），制动距离可达干燥路面的3-5倍，严重结冰时可能超过10倍。冰面行车应极度谨慎，车速控制在20-30km/h以下。",tip:"口诀：冰面刹车距离=干燥的3-10倍。冰面上最好别开，必须开=极慢（<30码）。"},
{id:343,cat:"weather",type:"judgment",q:"雪天行车时，应沿前车车辙行驶，避免开辟新路。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"雪天沿前车车辙行驶可降低打滑风险——前车已压实的雪路面比松散新雪有更好的附着力，且车辙提供了前进的轨道引导。",tip:"口诀：雪天走路走别人走过的——沿着车辙走，安全有保障。"},
{id:344,cat:"weather",type:"choice",q:"夜间在窄路、窄桥与非机动车会车时，应如何使用灯光？",opts:["继续使用远光灯","使用近光灯","关闭所有灯光","闪烁远光灯"],ans:1,exp:"窄路窄桥会车时用近光灯——远光会使对向非机动车驾驶人短暂失明，可能导致骑车人因看不清路况而摔倒，应特别注意。",tip:"口诀：窄路会车（不管对象是啥车）=近光灯。照顾对向交通参与者。"},
{id:345,cat:"weather",type:"choice",q:"在道路上遇到「水滑」现象（轮胎完全浮在水膜上失去抓地力）时，正确的应对措施是？",opts:["急踩刹车","紧握方向盘，松开油门，让车速自然降低","猛打方向","加速脱离水膜"],ans:1,exp:"水滑（Hydroplaning）发生时，轮胎与路面完全失去接触，此时刹车和转向均无效。正确做法：握紧方向盘保持直线→松油门让车速自然降低→等待轮胎重新接触路面。急刹或打方向在恢复抓地的瞬间可能导致失控。",tip:"口诀：水滑=握紧方向+松油门+等速度降下来。别刹车别打方向，等轮胎重新接地。"},
{id:346,cat:"weather",type:"judgment",q:"夏季高温天气驾车，轮胎胎压应适当调低以减少爆胎风险。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"胎压应按厂家推荐值保持，不应随意调低。胎压过低反而使轮胎侧壁过度弯曲变形，高速行驶时产生大量热量，增加爆胎风险。保持标准胎压最安全。",tip:"口诀：胎压别乱调，按厂家推荐值来。过低反而更易爆——轮胎一弯就发热。"},
{id:347,cat:"weather",type:"choice",q:"车辆驶出隧道时，由于眼睛从暗到亮的适应需要时间，这种现象被称为什么？正确的应对方法是什么？",opts:["黑洞效应，加速通过","白洞效应，适当减速，适应后再加速","红眼效应，戴墨镜","光晕效应，闭眼通过"],ans:1,exp:"隧道出口的强烈光线使驾驶人产生短暂视觉障碍，称为「白洞效应」。出隧道前应略微减速，给眼睛2-3秒适应时间，确认安全后再恢复车速。与进隧道时的「黑洞效应」相对。",tip:"口诀：进隧道=黑洞效应→减速；出隧道=白洞效应→减速。进出都要慢。"},
{id:348,cat:"weather",type:"choice",q:"在高速公路上遇到团雾（局部浓雾）时，以下做法正确的是？",opts:["加速冲出团雾区域","立即减速，开启所有灯光（除远光），握紧方向，避免急刹","保持远光灯照明冲出","靠边停车等雾散"],ans:1,exp:"团雾=「高速公路上的流动杀手」。进入团雾瞬间速度骤降极易被后车追尾。正确做法：看见团雾预警标志后提前减速→进入团雾后开所有灯（远光除外）→握紧方向匀速通过→绝对避免急刹。",tip:"口诀：团雾=提前减速+开灯+匀速走+别急刹。团雾中急刹=被后车撞。"},
{id:349,cat:"weather",type:"judgment",q:"在沙尘暴天气中行车，如果沙尘严重影响视线，应选择安全地点停车等待，并开启示廓灯和危险报警闪光灯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"沙尘暴严重影响视线时，应找安全地点停车等待（远离树木、广告牌等可能倒塌的物体），开启示廓灯和双闪。沙尘暴往往来快去也快，等一等最安全。",tip:"口诀：沙尘暴=开灯+找安全地（远离树/广告牌）+停车等。别硬着头皮开。"},
{id:350,cat:"weather",type:"choice",q:"在山区道路上，下长坡时如果刹车系统过热导致制动效能下降（热衰减），正确的紧急应对措施是什么？",opts:["继续踩刹车","抢挂低挡利用发动机制动，同时寻找紧急避险车道","拉起手刹","关闭发动机"],ans:1,exp:"刹车热衰减极其危险。应：①抢挂低速挡利用发动机制动→②寻找「紧急避险车道」（上坡砂石路，专为刹车失灵车辆准备的救命车道）→③万不得已时利用山体摩擦减速。",tip:"口诀：下坡刹车没了→抢低挡→找避险车道（上坡沙石路）。山区避险车道=救命坡。"},
{id:351,cat:"weather",type:"judgment",q:"在坡道上停车时，除了拉手刹外，还应将方向盘向路边方向打（上坡停车方向向左打、下坡停车方向向右打），挂上挡（手动挡）或P挡（自动挡），并用石块等塞住车轮。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"坡道停车防溜车三重保险：手刹+方向打向路边（万一溜车会撞到路沿石停下）+挂挡/P挡+塞车轮。上坡停车前轮向左打，下坡停车前轮向右打。",tip:"口诀：坡道停车=手刹+打方向+挂挡/塞石头。上坡左打，下坡右打。"},
{id:352,cat:"weather",type:"choice",q:"车辆行经施工路段时，正确的做法是？",opts:["加速通过","按照施工标志指示减速慢行，注意施工人员和设备","逆行绕过施工区","鸣喇叭催促施工人员让路"],ans:1,exp:"行经施工路段=按标志指示减速慢行+注意施工人员+不得随意变道+禁止超车。施工区限速一般为30km/h或按施工标志指示。",tip:"口诀：施工路段=慢+看标志+不超车。施工工人也是人，减速是对他们安全的尊重。"},
{id:353,cat:"weather",type:"judgment",q:"夜间通过有交通信号灯控制的交叉路口，在绿灯亮时也应交替使用远近光灯示意。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"有信号灯的路口，按信号灯指示通行即可，不需要额外闪灯。夜间闪灯适用于无信号灯控制的路口。有信号灯的路口闪灯反而可能干扰其他驾驶人。",tip:"口诀：有灯路口看灯走，别乱闪灯。无灯路口才闪灯示意。"},
{id:354,cat:"weather",type:"choice",q:"在恶劣天气中驾驶，以下哪项最容易导致交通事故？",opts:["开得慢","保持大车距","车速过快且未保持安全距离","开灯行驶"],ans:2,exp:"恶劣天气中车祸的头号原因=速度过快+跟车过近。雨天制动距离延长、视线受限，仍以正常速度行驶极易追尾和失控。",tip:"口诀：恶劣天气出事故=快+近。雨雪雾天减速+拉大间距是王道。"},
{id:355,cat:"weather",type:"choice",q:"驶近急弯、坡道顶端等影响安全视距的路段时，正确的做法是什么？",opts:["保持高速通过","减速慢行并鸣喇叭示意","加速通过以缩短危险时间","靠左行驶以便观察"],ans:1,exp:"视距不良路段（急弯、坡顶）=减速慢行+鸣喇叭（或夜间闪灯）+靠右行。因为看不到对向来车，必须用声音和灯光发出预警。",tip:"口诀：看不见对面→减速+鸣笛（或闪灯）+靠右。让对方知道你要来了。"},
{id:356,cat:"weather",type:"judgment",q:"在高速公路上遇到大暴雨时，可以在应急车道上停车开启双闪等待雨停。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"暴雨不属于可以使用应急车道的「紧急情况」（车辆故障、事故、人员突发疾病等）。应减速慢行或从最近出口驶离高速到服务区等待。应急车道停车将被记9分。",tip:"口诀：大雨不能停应急道（记9分）。去服务区或驶离高速。下雨不构成占用应急车道的理由。"},
{id:357,cat:"weather",type:"choice",q:"在道路结冰的情况下，自动挡车辆起步时正确的做法是什么？",opts:["加大油门起步","如果有雪地模式则开启，轻踩油门缓慢起步","挂空挡滑行起步","正常D挡正常起步"],ans:1,exp:"冰面起步=用雪地模式（如有）或手动2挡起步→轻踩油门→缓慢松开刹车。雪地模式会降低起步时的扭矩输出，减少打滑。大油门起步只会让车轮原地空转。",tip:"口诀：冰面起步=雪地模式/2挡→极轻油门→慢慢来。大油门=车轮空转更滑。"},
{id:358,cat:"weather",type:"judgment",q:"雨天驾驶时，开启空调的除雾模式可以有效防止车窗起雾。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"空调开启A/C+暖风吹前挡风玻璃可有效除雾。A/C压缩机能去除空气中的湿气，暖风加速玻璃升温防凝结。车窗起雾严重影响视线，应及时清除。",tip:"口诀：雨天防雾=A/C+暖风吹玻璃。A/C不只在夏天有用，除雾时也是神器。"},
{id:359,cat:"weather",type:"choice",q:"夜间行驶中，以下哪种做法能有效减轻对向远光灯造成的眩目影响？",opts:["也开远光灯回敬对方","视线向右偏移看道路右侧边缘线，同时减速","闭上一只眼睛","伸头到窗外看路"],ans:1,exp:"被远光眩目=视线右移看道路右侧边缘线（用边缘线判断车身位置）+减速+必要时靠边停车。不要也开远光回敬（双方都失明更危险）。",tip:"口诀：被远光晃→看右边白线→减速→稳住方向。别瞪回去，保自己的命要紧。"},
{id:360,cat:"weather",type:"judgment",q:"在高速公路上遇到降雪，路面开始积雪时，应开启雪地模式（如有）、控制车速在60km/h以内、与前车保持150米以上距离。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路降雪后路面湿滑系数大幅下降，应大幅降低车速（不超过60km/h甚至更低）、拉大车距（至少150米以上）、避免急操作。如路面积雪结冰严重，应尽快驶离高速。",tip:"口诀：高速遇雪=慢（≤60）+远（≥150米）+稳（不急操作）。雪大了赶紧下高速。"},

// ═══════════════════════════════════════════════════════════════
// 九、紧急情况处置 (emergency) — 40题 (361-400)
// ═══════════════════════════════════════════════════════════════
{id:361,cat:"emergency",type:"choice",q:"行车中发生爆胎时，驾驶人首先应当怎么做？",opts:["紧急制动","迅速向相反方向转向","紧握方向盘控制行驶方向","弃车逃生"],ans:2,exp:"爆胎第一步=紧握方向盘保持直线（最关键！）→松油门利用发动机制动缓慢减速→车速降低后轻踩刹车靠边停车。绝不能急刹或猛打方向——爆胎瞬间车辆已有偏转趋势，急操作=失控。",tip:"口诀：爆胎=握紧方向→松油门→慢减速→轻刹车靠边。爆胎不急刹+不急打方向！"},
{id:362,cat:"emergency",type:"choice",q:"车辆行驶中制动突然失灵，应如何操作？",opts:["立即熄火","抢挂低速挡利用发动机制动","跳车","等待自然停下"],ans:1,exp:"刹车失灵=①抢挂低挡（逐级降挡）利用发动机制动→②反复踩踏制动踏板尝试建压→③间歇拉动驻车制动（手刹）辅助减速（不能一下拉死，否则甩尾）→④必要时利用路侧护栏/山体摩擦减速。",tip:"口诀：刹车失灵→抢低挡→拉手刹（间歇拉）→蹭护栏（最后手段）。紧张但不能慌。"},
{id:363,cat:"emergency",type:"choice",q:"车辆发生火灾时，以下哪种做法是错误的？",opts:["立即关闭发动机","用灭火器灭火","打开发动机罩查看火情","疏散乘员"],ans:2,exp:"车辆起火打开发动机罩=给火大量氧气→火势瞬间猛增。正确做法：停车熄火→疏散人员→报警→对准发动机罩缝隙喷入灭火器→用灭火器时站在上风方向。",tip:"口诀：车起火别掀引擎盖！掀盖=火变大。从缝隙喷灭火器，站在上风口。"},
{id:364,cat:"emergency",type:"judgment",q:"雨天车辆在泥泞路段发生侧滑时，应向侧滑相反方向转动方向盘进行修正。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"侧滑的修正方向与车尾甩出方向一致（同向），而非相反。车尾往右甩，方向往右轻打。反方向打方向盘会加剧侧滑。",tip:"口诀：车尾往哪甩，方向往哪打（同向轻打）。千万不要反打！"},
{id:365,cat:"emergency",type:"choice",q:"在高速公路上行驶中，突然发现前方有障碍物，正确的做法是什么？",opts:["急打方向绕开","紧急制动","双手紧握方向盘，轻踩制动减速，在确保安全的前提下小角度避让","加速冲过去"],ans:2,exp:"高速遇障碍=握紧方向+减速+小角度避让。急打方向在高速下极易翻车；急刹可能被追尾；如果避让不及，宁可减速正面撞上障碍物（有安全带+气囊保护）也不要猛打方向（侧翻/失控更致命）。",tip:"口诀：高速遇障碍=握方向→减速→小角度避让。避不开就减速正面撞，别打方向翻车。"},
{id:366,cat:"emergency",type:"choice",q:"机动车落水后，正确的自救方法是什么？",opts:["立即打开车门逃生","等水灌满车厢内外水压平衡后再打开车门或破窗逃生","打电话求救等待救援","关闭所有车窗等待救援"],ans:1,exp:"车辆落水后，外部水压极大，车门无法推开。正确做法：①趁电路未短路立即开窗或用破窗锤破窗→②如车窗无法打开，等车内进水至接近车外水位（此时内外水压平衡，车门可推开）→③深吸一口气潜水从车门或车窗逃生。",tip:"口诀：车落水→先开窗/破窗→开不了就等水灌满（水压平衡）→深吸气潜水游出。车中常备破窗锤！"},
{id:367,cat:"emergency",type:"judgment",q:"车辆燃油泄漏着火时，可以使用水来灭火。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"燃油着火禁止用水灭火——油比水轻，浇水会使燃烧的油浮在水面上四处流淌，扩大火灾范围。应使用干粉灭火器、泡沫灭火器或沙土覆盖灭火。",tip:"口诀：油着火不能用水（油浮水面火乱跑），用干粉/泡沫灭火器或沙土。"},
{id:368,cat:"emergency",type:"choice",q:"行车中发现行人突然横穿马路，已经来不及避让，正确的做法是？",opts:["急打方向避让","急刹车并紧握方向盘，尽最大可能降低碰撞速度","加速冲过去","闭上眼睛"],ans:1,exp:"无法避让=全力制动降低碰撞速度+紧握方向保持车辆稳定。宁可正面碰撞也不要猛打方向（可能导致车辆失控冲入对向车道或撞到其他车辆/行人，后果更严重）。",tip:"口诀：避不开=死踩刹车减速+握紧方向。不猛打方向——撞一个比撞一片强。"},
{id:369,cat:"emergency",type:"choice",q:"在高速公路行驶中，车辆水温表指向红色区域（过热），正确的做法是？",opts:["立即熄火","靠边停车，怠速运转，打开发动机罩散热，不要立即熄火","继续行驶到服务区","加速行驶让风冷降温"],ans:1,exp:"发动机过热=安全靠边停车→怠速运转（保持水泵运转循环降温）→打开发动机罩加速散热→不要立即熄火（熄火后水泵停转，局部温度可能更高）→水温下降后再熄火检查冷却液。",tip:"口诀：水温过热→停车+怠速散热→开盖→不熄火。马上熄火=水泵停=局部更热。"},
{id:370,cat:"emergency",type:"judgment",q:"车辆电器设备起火时，应首先用水灭火。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"电器火灾禁止用水（水导电，可能导致触电或短路加重）。应先切断电源（关闭点火开关/断开电瓶负极），再用干粉灭火器或二氧化碳灭火器灭火。",tip:"口诀：电起火→先断电→再灭火（干粉/CO₂灭火器）。千万别用水！"},
{id:371,cat:"emergency",type:"choice",q:"夜间车辆灯光突然全部熄灭，应如何应对？",opts:["紧急制动停车","立即开启危险报警闪光灯，借助微弱光线观察路面，缓慢靠边停车","加速行驶找灯光","关闭所有开关重启"],ans:1,exp:"灯光全灭=立即开双闪（双闪由独立电路供电，通常不受灯光故障影响）→借助仪表盘微弱光线或路侧反光标识判断位置→缓慢减速靠边停车→设置警示标志。绝对不能急刹（后车看不到你）。",tip:"口诀：灯全灭→按双闪（独立电路）→慢慢靠边→放警示牌。别急刹——后面看不见你。"},
{id:372,cat:"emergency",type:"choice",q:"驾驶机动车在高速公路上行驶，方向盘突然剧烈抖动，可能是什么原因？正确的处理方式是什么？",opts:["正常现象，不用理会","轮胎不平衡或爆胎前兆，松油门缓慢减速靠边检查","加速通过","猛打方向纠正"],ans:1,exp:"高速行驶方向盘剧烈抖动=可能是轮胎问题（爆胎前兆、轮胎不平衡、轮胎鼓包、轮毂变形等）。正确做法：松油门缓减速→握紧方向→靠边停车检查。不要急刹或猛打方向。",tip:"口诀：高速方向抖=轮胎有问题。松油门+握方向+慢减速+靠边检查。"},
{id:373,cat:"emergency",type:"judgment",q:"发生交通事故后，搬运昏迷或有窒息危险的伤员时，应采用仰卧姿势，并保持呼吸道通畅。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"昏迷伤员=仰卧+头偏一侧+保持呼吸道通畅。意识不清者口腔内可能有呕吐物、分泌物或舌根后坠阻塞气道，必须确保呼吸道通畅。",tip:"口诀：昏迷=仰卧+头偏一侧+清口腔异物。呼吸道通畅是救命第一关。"},
{id:374,cat:"emergency",type:"choice",q:"机动车在高速公路上发生故障，需要停车排除故障时，应将车辆移至什么地方？",opts:["行车道","应急车道或者路肩","超车道","匝道"],ans:1,exp:"高速故障车辆应移至应急车道（硬路肩）停放，开启双闪，在来车方向150米外设置警告标志，车上人员转移至护栏外安全地带。",tip:"口诀：高速故障=移到应急车道（利用惯性尽量挪）→双闪→150米牌→人撤护栏外。"},
{id:375,cat:"emergency",type:"choice",q:"行车中与其他车辆发生正面碰撞且不可避免时，正确的紧急措施是什么？",opts:["闭上眼睛","紧急制动，同时将头后仰紧靠座椅头枕","急打方向避让","跳车"],ans:1,exp:"碰撞不可避=全力制动降低碰撞速度（速度越低伤害越小）+头紧贴座椅头枕（减少颈椎挥鞭伤）。安全带+气囊+头枕正确调节是在碰撞中保命的三大要素。",tip:"口诀：要撞了=死踩刹车减速+头贴头枕。头枕正确调节=头枕上缘与头顶齐平。"},
{id:376,cat:"emergency",type:"judgment",q:"机动车在高速公路上发生故障时，驾驶人可以在其他车辆的帮助下自行拖拽故障车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路故障车不得自行组织拖拽（危险性极大）。应由高速公路专业救援车辆（清障车）进行拖拽。应拨打12122高速救援电话。",tip:"口诀：高速拖车=12122叫专业救援，不许私自救。高速公路私自救=找死。"},
{id:377,cat:"emergency",type:"choice",q:"以下哪种情况最容易引发车辆侧翻？",opts:["直线匀速行驶","高速行驶中猛打方向","缓慢转弯","低速行驶"],ans:1,exp:"高速猛打方向=侧翻的主要原因。车辆重心（SUV/MPV更高）在高速急转时受离心力作用向外侧偏移，当离心力超过车辆稳定极限时即侧翻。高速避让时应以减速为主、转向为辅。",tip:"口诀：高速猛打方向=翻车。遇危险先减速再转向，不是先转向再减速。"},
{id:378,cat:"emergency",type:"choice",q:"救助有害气体中毒的伤员时，施救者首先应做好什么？",opts:["直接进入施救","做好自身防护（如用湿毛巾捂住口鼻、确认环境安全）后再施救","先打电话","先拍照"],ans:1,exp:"有害气体中毒施救=首先保护自己——用湿毛巾捂住口鼻、弯腰（有害气体多上浮）、确认无二次危险（爆炸、塌方等）后再接近伤员。救人先保己。",tip:"口诀：毒气救人=先护己→湿毛巾捂口鼻+弯腰低姿进入。别救人变被救。"},
{id:379,cat:"emergency",type:"judgment",q:"夜间行驶中，如果对向来车未关闭远光灯导致眩目，应立即紧急制动停车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"被远光眩目时急刹停车极其危险（后车可能追尾）。正确做法：减速+视线右移看道路右侧边缘线+保持方向稳住。如眩目严重可缓慢靠边停车等待恢复。",tip:"口诀：被远光闪→减速+看右边线→别急刹。后面还有车跟着你呢。"},
{id:380,cat:"emergency",type:"choice",q:"车辆在高速公路行驶中，发动机盖突然掀起遮挡前风挡玻璃，正确的应急措施是？",opts:["紧急制动停车","通过发动机盖与挡风玻璃之间的缝隙观察前方，开启右转向灯，缓慢减速靠边停车","打开车窗探头出去看路继续行驶","加速行驶甩开发动机盖"],ans:1,exp:"发动机盖掀起的视野缝隙通常在仪表台与前挡之间，可透过此缝隙观察前方。正确做法：开双闪→通过缝隙观察→开启右转向灯→缓慢减速靠边→停应急车道。不能急刹（高速+无视野=危险）。",tip:"口诀：机盖弹起=透过缝隙看路→双闪+右灯→慢靠边→停车处理。别急刹。"},
{id:381,cat:"emergency",type:"choice",q:"行车中仪表板上制动系统故障警告灯（红色感叹号或BRAKE灯）亮起，表示什么？",opts:["手刹没放","制动系统可能存在严重故障，应立即靠边停车检查","制动液需要更换","正常提示保养"],ans:1,exp:"制动系统警告灯亮=制动系统可能严重故障（制动液严重不足、制动管路泄漏、制动片磨损极限等）。应立即安全靠边停车检查，不可继续行驶。",tip:"口诀：制动红灯亮=立刻停车检查。刹车事关人命，不能有任何侥幸。"},
{id:382,cat:"emergency",type:"judgment",q:"车辆在高速公路上发生火灾时，如果火势已经无法控制，驾驶人应迅速弃车撤离到安全地带。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"火势失控=弃车保人。车辆可以再买，生命只有一次。迅速撤离到护栏外上风方向安全地带，然后报警。远离着火车辆（可能爆炸）。",tip:"口诀：大火灭不了=人快跑。往护栏外跑+往上风方向跑。车子别管了。"},
{id:383,cat:"emergency",type:"choice",q:"驾驶人在高速行车中发现车道前方有动物突然窜出，正确的处理方法是？",opts:["急打方向避让","紧急制动，在确保安全的前提下尽可能减速，切忌猛打方向","加速绕过","鸣喇叭驱赶"],ans:1,exp:"高速遇到动物突然窜出=减速（不要急刹到抱死）+握紧方向+不猛打方向。为避让一只动物而急打方向导致车辆失控侧翻的后果比撞上动物严重得多。优先保护人的安全。",tip:"口诀：高速有动物窜出→减速+打方向别太大。撞动物好过翻车。人命比动物命重要。"},
{id:384,cat:"emergency",type:"judgment",q:"车辆燃油耗尽停在高速公路行车道上时，驾驶人可以步行到最近的加油站买油。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"绝不能在高速公路行车道上停车，更不能在高速公路上步行（极其危险且违法）。燃油耗尽=尽可能将车移到应急车道→开双闪→设150米警示牌→人撤离到护栏外→打12122请求送油或拖车。",tip:"口诀：高速没油=挪应急车道→开灯设牌→人撤护栏外→叫救援。别自己走路买油！"},
{id:385,cat:"emergency",type:"choice",q:"在交通事故中，伤员呼吸心跳停止，开始心肺复苏的黄金抢救时间是多少？",opts:["10分钟","4-6分钟","30分钟","1小时"],ans:1,exp:"心跳骤停后4-6分钟为黄金抢救时间（脑细胞开始缺氧性损伤的临界时间）。超过6分钟脑损伤不可逆，10分钟后基本无生还可能。立即CPR是挽救生命的关键。",tip:"口诀：心跳停了=4-6分钟黄金窗口。立即按压！每等1分钟，存活率降10%。"},
{id:386,cat:"emergency",type:"choice",q:"机油压力警告灯在行驶中亮起，以下做法正确的是？",opts:["继续行驶找修理厂","立即安全靠边停车、熄火，检查机油量","加速行驶以尽快到达目的地","忽略不管"],ans:1,exp:"机油压力警告灯亮=机油压力不足，发动机内部可能正在发生严重磨损。继续行驶几分钟就可能造成发动机报废。应立即安全停车、熄火、检查机油。",tip:"口诀：机油灯亮=急停+熄火+查机油。再开几分钟=发动机报废。"},
{id:387,cat:"emergency",type:"judgment",q:"车辆发生侧滑时，如果是转向过度（后轮失去抓地力导致车尾甩出），应向车尾甩出的方向打方向盘。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"转向过度（后轮打滑/甩尾）=向车尾甩出的方向同向打方向，使车身回正。这是赛道和日常驾驶中通用的正确救车方法。",tip:"口诀：车尾往哪甩方向往哪打（顺势修正）。这是所有甩尾情况的通用公式。"},
{id:388,cat:"emergency",type:"choice",q:"驾驶人在行车中感到头晕、眼花、四肢无力等身体不适时，应怎么做？",opts:["坚持开到目的地","立即选择安全地点停车休息或寻求帮助","开窗通风继续驾驶","加速行驶尽快到达"],ans:1,exp:"身体不适=立即安全停车。身体突发状况（低血糖、高血压、心脏不适等）可能导致突然失去意识，后果不堪设想。安全停车后可拨打120或寻求他人帮助。",tip:"口诀：开车时身体不舒服=马上靠边停。硬撑可能下一秒就失去意识。"},
{id:389,cat:"emergency",type:"judgment",q:"车辆在高速公路上发生故障无法移动，在等待救援期间，所有人员应留在车内系好安全带等待。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速故障后人员必须离开车辆，转移到护栏外安全地带。留在车内是极其危险的——后方来车可能因未注意到故障车而发生二次碰撞，车内人员伤亡风险极高。",tip:"口诀：高速车坏了=人下车到护栏外。千万别坐车里等！二次碰撞专杀车里的。"},
{id:390,cat:"emergency",type:"choice",q:"以下关于紧急避险的表述，正确的是？",opts:["为了避让行人可以不顾一切冲入对向车道","紧急避险造成的损害不得大于所避免的损害","任何情况下都不能紧急避险","紧急避险不需要承担任何责任"],ans:1,exp:"紧急避险原则：避险造成的损害不得明显大于所避免的损害。例如不能为了避让一只狗而冲入人行道撞伤行人。紧急避险过失当的，仍应承担相应责任。",tip:"口诀：紧急避险=两害相权取其轻。保人命比保财物重要，保多人比保一人重要。"},
{id:391,cat:"emergency",type:"choice",q:"发现车辆有烧焦味或冒烟时，以下哪种做法最正确？",opts:["不管继续开","立即停车、熄火、断开电瓶（如安全）、疏散人员、查明原因","打开车窗通风继续开","加速到修理厂"],ans:1,exp:"烧焦味/冒烟=可能起火的先兆。应立即停车→熄火→疏散人员→在安全前提下断开电瓶负极（切断电源）→用灭火器准备灭火→查明原因或报警。",tip:"口诀：闻到焦味/看到烟=可能是火灾前兆。停车→熄火→断电→准备灭火。"},
{id:392,cat:"emergency",type:"judgment",q:"驾驶机动车在高速公路上发生爆胎后，切忌猛打方向和紧急制动。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速爆胎后猛打方向或急刹=瞬间失控翻车。正确做法：①紧握方向→②松油门→③车速自然降低→④轻踩刹车靠边。",tip:"口诀：爆胎后两不——不打方向、不急刹。稳住方向+松油门=保命。"},
{id:393,cat:"emergency",type:"choice",q:"车辆在夜间行驶时突然大灯熄灭，在开启危险报警闪光灯的同时，还可以借助什么来判断道路走向？",opts:["天上的星星","道路边缘的轮廓标、反光道钉和车道标线","手机屏幕","月亮光"],ans:1,exp:"夜间大灯熄灭=开双闪+利用道路反光设施（轮廓标、反光道钉、车道反光标线等）判断道路走向+缓慢靠边停车。高速公路两侧每隔一定距离设有反光轮廓标，车灯照射会反光。",tip:"口诀：灯灭了看路边反光物（轮廓标+道钉+标线反光）→它们会告诉你路在哪。"},
{id:394,cat:"emergency",type:"judgment",q:"雨天车辆发生侧滑时，如果车辆装有ESP（电子稳定程序），ESP系统会自动介入制动特定车轮来帮助稳定车身。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"ESP（车身电子稳定系统）在检测到侧滑时，会自动对单个或多个车轮施加制动力，并调整发动机扭矩输出，帮助驾驶人恢复对车辆的控制。但ESP也有物理极限，不能完全替代安全驾驶。",tip:"口诀：ESP=侧滑时自动帮你刹车纠正。但ESP不是万能的，超过了物理极限照样翻。"},
{id:395,cat:"emergency",type:"choice",q:"发生交通事故后，伤员出血量大且难以止血，在等待救护车的过程中，以下哪项措施最有助于防止失血性休克？",opts:["给伤员喝水","让伤员平躺，抬高下肢（促进血液回流心脏），保持体温","让伤员坐起来","给伤员吃止痛药"],ans:1,exp:"大出血=平躺+抬高下肢（休克体位）+保暖+止血。抬高下肢有助于血液回流心脏和大脑，延缓休克发生。不给伤员喝水或进食（可能需要紧急手术）。",tip:"口诀：大出血=平躺+抬腿+保暖+止血。别喂水（可能要手术）。休克体位=平躺腿抬高30cm。"},
{id:396,cat:"emergency",type:"judgment",q:"在高速公路上因故障停车后，可以用车上的备用轮胎或其他物品充当警告标志。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"警告标志必须使用符合国家标准的三角警示牌（反光型）。用轮胎、水桶等代替警示牌，反光效果不足，无法有效警示后方来车。车上应常备合格三角警示牌。",tip:"口诀：警示牌=专用反光三角牌。不能用轮胎/水桶代替！后备箱标配三角牌。"},
{id:397,cat:"emergency",type:"choice",q:"车辆行驶中，油门踏板卡住无法回位（持续给油），以下哪种做法最危险？",opts:["挂空挡切断动力","关闭发动机","猛踩刹车同时继续加油","用脚把油门踏板勾回"],ans:2,exp:"油门卡住=①立即挂N挡（自动挡）或踩离合（手动挡）切断动力→②开启双闪→③平稳刹车靠边→④停车后熄火。最危险的做法是：同时猛踩刹车（发动机仍在给油，与刹车对抗，制动距离显著延长）。",tip:"口诀：油门卡住=挂N挡/踩离合断动力→开双闪→刹车靠边→熄火。别边加油边刹车！"},
{id:398,cat:"emergency",type:"judgment",q:"车辆冲入水中后，由于电路可能很快短路，应优先尝试电动车窗或天窗逃生。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"车辆落水后电路通常还能维持1-2分钟（部分车型更长），此时应首先尝试开窗或开天窗逃生。车窗无法打开时，用破窗锤敲击侧窗四角（中间钢化玻璃最坚固）。前挡风玻璃是夹层玻璃，敲碎了也推不开。",tip:"口诀：落水=第一时间开窗/天窗→不行就破窗锤砸侧窗四角→别砸前挡（夹层玻璃砸不穿）。"},
{id:399,cat:"emergency",type:"choice",q:"在高速公路上遇到「团雾」，进入团雾后能见度突然降至不足10米时，以下正确的做法是？",opts:["立即急刹车","开启所有灯光（除远光），以极慢的速度尝试沿道路标线行驶至最近停车带或出口","加速冲出团雾","在行车道上停住不动"],ans:1,exp:"团雾能见度极低（<10米）=开所有灯（远光除外）→超低速（5-10km/h）沿道路右侧边线行驶→尽快找到停车带或出口。不能停在行车道上——后面来车也看不见你。",tip:"口诀：团雾中=开灯+贴着右边线蜗牛速度走→找停车带/出口。不能停行车道。"},
{id:400,cat:"emergency",type:"judgment",q:"车辆发生碰撞后，如果车门无法打开，可以用安全锤敲击车窗四角逃生。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"钢化玻璃侧窗的四角最为脆弱，用安全锤/头枕金属杆敲击四角容易破碎。前挡风玻璃是夹层玻璃（两层玻璃中间夹塑胶膜），敲碎也无法推开，应选择侧窗逃生。",tip:"口诀：敲窗逃=敲侧窗四角（钢化玻璃），别敲前挡（夹层玻璃敲不穿）。车上备个破窗锤。"},

// ═══════════════════════════════════════════════════════════════
// 十、新能源汽车 2026新增 (ev) — 30题 (401-430)
// ═══════════════════════════════════════════════════════════════
{id:401,cat:"ev",type:"choice",q:"新能源汽车在充电时，以下哪种做法是正确的？",opts:["使用非标充电设备","在暴雨天气露天充电","使用符合国标的充电桩，充电枪完全插入后再启动充电","边充电边洗车"],ans:2,exp:"新能源汽车充电应使用符合国家标准（GB/T）的充电桩，充电枪完全插入锁止后再启动。暴雨天不建议露天充电（虽然有一定防水等级，但仍有风险）。充电过程中不得洗车。",tip:"口诀：充电=国标桩+枪插到位+雨天不露天充。安全充电是第一。"},
{id:402,cat:"ev",type:"choice",q:"新能源汽车动力电池在高温天气下，以下哪种情况需要特别注意？",opts:["电池会自动降温不需要注意","长时间暴晒后立即快充可能触发电池过热保护","高温对电池没有影响","高温能提升电池性能"],ans:1,exp:"高温暴晒后电池温度较高，立即进行大功率快充可能触发BMS（电池管理系统）的过热保护限制充电功率，甚至暂停充电。建议待电池降温后再充电。",tip:"口诀：暴晒后别马上快充→电池太烫→BMS保护→充电变慢或停充。凉一凉再充。"},
{id:403,cat:"ev",type:"choice",q:"新能源汽车在涉水行驶时，以下哪种说法是正确的？",opts:["电动车不怕水可以随意涉水","纯电动车涉水深度一般不超过30cm（参照使用手册），低速匀速通过","电动车涉水性能和燃油车完全不同可以潜很深","电车在水里可以正常行驶"],ans:1,exp:"纯电动车虽然不需要进气（无发动机），但仍有限定的涉水深度（通常不超过30cm，具体参照手册），因为电池组、高压线束、电机等部件有防水等级限制（一般为IP67）。涉水过深可能导致高压系统进水短路。",tip:"口诀：电车涉水<30cm（看手册），虽不进气但高压怕水。过深涉水=电池进水=报废+危险。"},
{id:404,cat:"ev",type:"judgment",q:"新能源汽车在充电过程中，可以在车内开启空调休息。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"新能源车充电时可以开启空调（使用充电桩供电而非电池），但出于安全和充电效率考虑，不建议长时间在充电时待在车内。极端情况下（老旧设备、非标桩），充电时车内存在电磁辐射和轻微安全风险。",tip:"口诀：充电开空调可以但不建议。安全起见，充电时下车活动一下。"},
{id:405,cat:"ev",type:"choice",q:"新能源汽车仪表盘上显示「乌龟」图标（功率限制指示灯）亮起，表示什么？",opts:["车辆进入运动模式","动力系统受限，输出功率被限制，应减速慢行并尽快检修","定速巡航已激活","需要更换电池"],ans:1,exp:"乌龟灯=动力系统故障或电池电量极低/温度异常→输出功率被严重限制→车辆只能低速行驶（如30-50km/h）→应尽快安全靠边或驶向最近维修站。",tip:"口诀：乌龟灯=动力被限（电池/电机出问题）。龟速行驶→赶紧修。"},
{id:406,cat:"ev",type:"judgment",q:"新能源汽车长时间不用时，应保持电池电量在50%-80%之间，避免满电或亏电长时间存放。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"锂电池长时间存放最佳电量区间=50%-80%。满电（100%）长期存放会加速电池衰减；亏电（<10%）长期存放可能导致电池过放电损坏。推荐每3个月充放电一次以保持电池活性。",tip:"口诀：长期不开=电量保持50%-80%=电池最舒服。满电/亏电存放=电池短命。"},
{id:407,cat:"ev",type:"choice",q:"新能源汽车的「再生制动」（能量回收）功能有什么作用？",opts:["增加油耗","将制动时产生的动能转化为电能回充电池，同时辅助减速","让车辆加速更快","完全没有作用"],ans:1,exp:"再生制动（Regenerative Braking）=松开油门或踩刹车时，驱动电机转为发电机模式，利用车辆惯性动能发电回充电池，同时产生制动力辅助减速。可延长续航里程并减少刹车片磨损。",tip:"口诀：能量回收=松油门就充电+辅助减速。滑行也在攒里程。"},
{id:408,cat:"ev",type:"choice",q:"新能源汽车电池组发生高温起火时，以下哪种处理方式是正确的？",opts:["用干粉灭火器近距离灭火","用水灭火","立即停车疏散人员，远离车辆（至少15米），拨打119并告知是新能源车起火","打开引擎盖自行检查"],ans:2,exp:"动力电池（锂电池）起火=极难扑灭（自带氧化剂，不用空气也能燃烧）。正确做法：①立即停车→②全员远离（至少15米以上，电池起火可能喷射火焰和有毒气体）→③拨打119并明确告知「新能源车电池起火」（消防需专门处置方案）→④不要自行灭火。",tip:"口诀：电池起火=人跑远+119说清楚是电车。锂电池起火极难灭，专业的事交给消防。"},
{id:409,cat:"ev",type:"judgment",q:"新能源汽车的续航里程在冬季低温天气会明显缩短，这是正常现象。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"低温下锂电池化学反应活性降低+空调制热耗电=续航通常缩短20%-40%。这是锂电池的物理特性，非故障。冬季应预留更多续航余量，提前规划充电。",tip:"口诀：冬天续航打6-8折=正常（电池怕冷）。冬天出门多留续航余量。"},
{id:410,cat:"ev",type:"choice",q:"以下关于新能源车「快充」和「慢充」的表述，哪项是正确的？",opts:["频繁使用快充对电池寿命无影响","快充比慢充对电池更友好","建议日常使用慢充为主、快充为辅，以延长电池寿命","只能使用快充"],ans:2,exp:"快充（直流大功率）会使电池温度升高，长期频繁快充加速电池衰减。日常应以慢充（交流充电）为主（对电池最友好），快充作为长途出行补充。厂家通常建议快充比例不超过总充电次数的30%-50%。",tip:"口诀：日常慢充为主（保护电池）、长途快充为辅。慢充养电池，快充应急用。"},
{id:411,cat:"ev",type:"judgment",q:"新能源车在冬季冷启动时，需要像燃油车一样长时间热车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"电动车不需要热车——电机不存在机油润滑和预热需求。但冬季低温时电池温度低会影响输出功率和续航，部分车型有电池预热功能（在充电时或行驶前对电池加温以提高性能）。",tip:"口诀：电车不用热车（没有发动机）。但电池冷了影响续航，有的车会自动预热电池。"},
{id:412,cat:"ev",type:"choice",q:"纯电动汽车的「蠕行」功能是指在D挡或R挡时，松开制动踏板但不踩加速踏板，车辆会以很低的速度缓慢移动。此功能类似于传统燃油自动挡汽车的什么特性？",opts:["涡轮增压","怠速蠕行","定速巡航","ABS"],ans:1,exp:"电动车蠕行功能=模拟燃油自动挡汽车挂D挡松刹车后的怠速前进。该功能在低速挪车和跟车时提供了自然的操作感受。部分电动车可设置蠕行功能的开/关。",tip:"口诀：电车蠕行=D挡松刹车慢慢走，模拟油车怠速感。停车入库时蠕行很实用。"},
{id:413,cat:"ev",type:"choice",q:"新能源汽车在充电时，充电枪无法拔出（锁止），可能的原因是什么？",opts:["充电枪坏了","车辆未解锁或充电未停止，充电枪电子锁止装置仍处于锁定状态","充电桩坏了","需要大力拔出"],ans:1,exp:"充电枪有电子锁止装置（防止充电中意外拔出）。如无法拔出：①确认已通过APP或车内按钮停止充电→②用遥控钥匙解锁车辆→③如仍无法拔出，使用应急机械拉索释放锁止（参照使用手册）。不要暴力拔出。",tip:"口诀：充电枪拔不出→停止充电→解锁车门→还不行就找应急拉索。别用蛮力！"},
{id:414,cat:"ev",type:"judgment",q:"新能源车可以驶入水深超过50cm的积水路段，因为电动机不需要空气来运转。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"虽然电动机不需要空气，但电池组高压线束和电控系统的防水等级有限（通常IP67=浸水1米/30分钟）。50cm水深已远超多数车型的安全涉水深度。涉水过深可能导致高压系统进水短路、电击风险以及车辆漂浮失控。",tip:"口诀：电车也不能当潜水艇。高压怕水，涉水深度同样有限。"},
{id:415,cat:"ev",type:"choice",q:"新能源汽车仪表盘上显示电池电量SOC为0%时，实际上电池还有多少电量？",opts:["完全没有电了","为了保护电池，BMS会保留一定电量（通常3%-5%左右）","还有50%","还能跑100公里"],ans:1,exp:"SOC显示0%≠电池完全没电。BMS会预留少量电量（约3%-5%）作为保护缓冲区，防止电池过放电损坏。SOC到0%后车辆通常还能极低速行驶数公里（「跛行模式」），但应立即寻找充电桩。",tip:"口诀：SOC 0%=还有一丢丢（3-5%保护余量），能再挪几公里找充电桩。但别常这样，伤电池。"},
{id:416,cat:"ev",type:"choice",q:"关于新能源车的保养，以下说法正确的是？",opts:["不需要任何保养","仍然需要定期保养：包括检查高压系统、更换齿轮油、空调滤芯、制动液等","只需换机油","每年必须更换电池"],ans:1,exp:"新能源车虽无需更换机油，但仍需定期保养：检查高压线束和接插件、更换减速器齿轮油、制动液、空调滤芯、轮胎换位、检查底盘电池组等。保养周期通常为1年或2万公里（参照手册）。",tip:"口诀：电车也要保养（不是不用保养）。不换机油但检高压+换齿轮油+刹车油+滤芯。"},
{id:417,cat:"ev",type:"judgment",q:"新能源车下雨天可以在室外使用充电桩充电，不需要担心安全问题。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"国标充电桩和充电接口通常设计有≥IP54的防水等级（防溅水），小雨天气充电一般是安全的。但雷暴雨天气不建议户外充电——充电枪与车身接口处可能进水导致短路，且雷击风险增加。安全起见，暴雨时暂停充电。",tip:"口诀：小雨充电可以（有防水设计），暴雨/雷电别充。安全比充满电重要。"},
{id:418,cat:"ev",type:"choice",q:"新能源车在行驶中因电量耗尽（「趴窝」）停在路上，正确的处理方式是？",opts:["推车到充电站","开启双闪，在来车方向设置警告标志，人员撤离到安全地带，呼叫道路救援","坐在车内等待路过车辆帮助","自行拦车帮忙拖拽"],ans:1,exp:"电车电量耗尽=开启双闪→来车方向设警示牌（高速150米/普通50-100米）→人员撤离到安全地带→呼叫道路救援（保险公司或充电运营商的移动充电救援服务/拖车至最近充电站）。",tip:"口诀：电耗尽趴窝=开双闪+放警示牌+人撤离+叫救援。别自己推，别拦车拖。"},
{id:419,cat:"ev",type:"judgment",q:"氢燃料电池汽车（FCEV）的排放物是水蒸气，属于零排放汽车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"氢燃料电池汽车通过氢气与氧气在燃料电池堆中发生电化学反应产生电能驱动电机，唯一的排放物是水蒸气（H₂O），真正实现零碳排放。但需要注意氢气的制取过程是否清洁。",tip:"口诀：氢燃料电池车=加氢→发电→排水蒸气。零排放，但氢气本身制取要环保才行。"},
{id:420,cat:"ev",type:"choice",q:"新能源车在冬季使用空调暖风时，以下哪种方式最节能？",opts:["一直开到最高温度","使用座椅加热和方向盘加热替代或辅助空调暖风，可大幅降低能耗","打开车窗通风","不开暖风硬扛"],ans:1,exp:"空调暖风是电动车冬季续航的最大消耗之一。使用座椅加热+方向盘加热（直接接触式取暖）比加热整个车厢更节能（耗电量约为空调暖风的1/5-1/10）。合理使用可显著延长续航。",tip:"口诀：冬天保暖=座椅加热+方向盘加热比吹暖风省电多得多。暖屁屁比暖全车节能。"},
{id:421,cat:"ev",type:"judgment",q:"纯电动汽车在长下坡路段可以利用再生制动（能量回收）功能，在辅助减速的同时回收电能。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"长下坡=再生制动的理想场景。松开加速踏板后电机转为发电模式，利用车辆重力势能发电回充电池，同时提供类似发动机制动的减速效果。下完长坡后续航里程可能反而增加了。",tip:"口诀：下长坡=电车赚里程。松油门→发电+减速，下完坡电量反而多了。"},
{id:422,cat:"ev",type:"choice",q:"以下关于新能源车与燃油车在隧道内行驶的区别，哪项是正确的？",opts:["电车不需要开灯","电车和燃油车一样，隧道内必须开启近光灯","电车可以比油车开得更快","电车在隧道里需要关闭空调"],ans:1,exp:"电车在隧道内的行驶规则与燃油车完全相同——必须开启近光灯、不得超车、按限速行驶、保持安全距离。新能源车不享有任何特权。",tip:"口诀：隧道规则电车和油车一样。开灯+不超车+限速。电车不是特权车。"},
{id:423,cat:"ev",type:"choice",q:"新能源车仪表上显示「READY」灯亮起（无论是否听到声音），表示什么？",opts:["车辆故障","车辆已启动，高压系统接通，可挂挡行驶","正在充电","电池没电了"],ans:1,exp:"「READY」灯=电动车已启动（高压系统上电），可挂挡行驶。电动车没有发动机怠速声，READY灯替代了油车的「发动机运转」感知。下车前务必确认READY灯已熄灭（车辆已断电）。",tip:"口诀：READY灯亮=电车已启动（虽然静悄悄）。下车前一定确认READY灯灭了。"},
{id:424,cat:"ev",type:"judgment",q:"新能源车充电时可以同时进行车辆软件OTA升级。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"大多数新能源车在充电期间不推荐进行OTA升级——OTA升级过程中车辆部分系统不可用（包括充电管理），可能导致充电中断或升级失败。应分别进行充电和升级操作。",tip:"口诀：充电时不OTA升级，升级时不充电。两个操作分开做，互不干扰。"},
{id:425,cat:"ev",type:"choice",q:"新能源汽车出现高压系统故障警告（如红色电池图标+感叹号），驾驶人应如何处理？",opts:["继续正常行驶","立即安全靠边停车、全车断电、疏散人员、联系专业维修人员，不要自行触摸高压部件","自己打开电池组检查","加速驶往修理厂"],ans:1,exp:"高压系统故障警告=可能涉及高压漏电或电池严重故障。应立即：安全停车→全车断电→全员下车远离→联系专业维修（不要自行触碰任何橙色高压线束和部件，高压电可致命）。",tip:"口诀：高压故障红灯=立即停车+断电+人离开+叫专业维修。别摸橙色线（高压）！"},
{id:426,cat:"ev",type:"choice",q:"关于新能源汽车的「单踏板模式」(One-Pedal Driving)，以下哪项描述正确？",opts:["车辆只有一个踏板","松开加速踏板时车辆会强烈减速（再生制动），可实现大部分情况下不踩制动踏板","不需要刹车踏板","任何时候都不能使用刹车"],ans:1,exp:"单踏板模式=松开加速踏板时电机产生较强的再生制动力使车辆明显减速，在大多数跟车减速场景下不需切换踩制动踏板。但紧急情况仍需踩制动踏板——单踏板不能完全替代刹车，制动踏板永远保留。",tip:"口诀：单踏板=松油门就强减速+充电。但不是没刹车踏板！紧急情况还是要踩刹车。"},
{id:427,cat:"ev",type:"judgment",q:"新能源车在高速公路服务区的充电站充电时，车主可以离开车辆去休息或吃饭。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"虽然技术上可以在充电时离开车辆，但不建议——充电过程中可能出现异常（充电中断、过热等），最好保持通讯畅通并定期检查。另外充电完成后应及时挪车让出充电位（避免占位费/影响他人）。",tip:"口诀：充电时最好不远离。充满了及时挪车，别占位——有的超时会收高额占位费。"},
{id:428,cat:"ev",type:"choice",q:"以下哪种做法会加速新能源汽车动力电池的衰减？",opts:["浅充浅放（20%-80%区间）","经常把电量用到0%再充满（深充深放）","使用慢充充电","在适宜温度下使用"],ans:1,exp:"深充深放（0%-100%）对锂电池寿命最不友好——电池在极低和极高电量状态时化学反应活性最强，会加速电极材料老化。最佳使用区间为20%-80%（浅充浅放），可显著延长电池寿命。",tip:"口诀：电池最怕=经常用到0%再充到100%。最舒服=20%-80%区间用+慢充。"},
{id:429,cat:"ev",type:"judgment",q:"混合动力汽车（HEV/PHEV）在纯电模式下行驶时，行人可能听不到车辆靠近的声音，因此法规要求这类车辆在低速行驶时发出警示音。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"低速行驶警示音（AVAS）=法规强制要求纯电动和混合动力汽车在低速（通常<20-30km/h）时通过车外扬声器发出警示音，提醒行人注意车辆接近。车速提高后胎噪和风噪足够大，警示音自动关闭。",tip:"口诀：电车太安静→低速自动发声提醒行人。听到「嗡嗡」声=电车来了。"},
{id:430,cat:"ev",type:"choice",q:"新能源车在停车时，以下哪种操作最有利于保护动力电池？",opts:["随便怎么停都行","长时间停放时保持电量在50%-80%，停放在阴凉通风处（避免暴晒和严寒）","必须每天充满电","放在太阳下暴晒充电"],ans:1,exp:"保护电池的停放=电量50%-80%+阴凉通风处（15-30℃环境最佳）+避免高温暴晒和严寒。高温是锂电池寿命的头号杀手，其次是满电/亏电存放。",tip:"口诀：停车养电池=半电（50-80%）+阴凉处。暴晒+满电=电池短命套餐。"},

// ═══════════════════════════════════════════════════════════════
// 十一、智能驾驶辅助 2026新增 (smart) — 25题 (431-455)
// ═══════════════════════════════════════════════════════════════
{id:431,cat:"smart",type:"choice",q:"自适应巡航控制系统（ACC）的主要功能是什么？",opts:["让车辆自动驾驶","自动保持与前车的安全距离，并根据前车速度自动调整本车速度","让车辆自动转向","自动变道超车"],ans:1,exp:"ACC（Adaptive Cruise Control）=在设定巡航速度内自动保持与前车的安全距离，前车减速时自动跟减，前车加速或驶离后自动恢复设定速度。ACC只管纵向速度，不管横向（转向）。",tip:"口诀：ACC=自动跟车（调速度+保距离）。不管方向！手还是要握方向盘的。"},
{id:432,cat:"smart",type:"choice",q:"车道保持辅助系统（LKA/LCC）在什么情况下可能失效？",opts:["任何天气都正常工作","雨雪雾天气、车道标线模糊或缺失、强光直射摄像头时可能失效","只在下雨时失效","永远不会失效"],ans:1,exp:"LKA/LCC靠前视摄像头识别车道标线。车道线模糊/缺失、雨雪覆盖路面、强光/逆光照射摄像头、大雾等情况都会导致系统无法识别车道，功能自动退出并提醒驾驶人接管。",tip:"口诀：LKA怕=标线看不清（雨雪雾/旧路磨没了/逆光）。系统退出时滴滴响=叫你赶紧接管。"},
{id:433,cat:"smart",type:"judgment",q:"2026年市场上的「自动驾驶」功能可以完全替代驾驶人，驾驶人可以在开启后睡觉或离开驾驶座。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"截至2026年，中国市场上所有量产乘用车均为L2级辅助驾驶（部分L2+），没有任何车型达到真正的L3级以上自动驾驶。驾驶人必须全程监控路况、手握方向盘、随时准备接管。任何宣称「可以完全不管」的都是误导。",tip:"口诀：2026年没有真正的自动驾驶（都是辅助驾驶）。手不离方向、眼不离路面、随时接管。别被「自动驾驶」营销骗了。"},
{id:434,cat:"smart",type:"choice",q:"使用ACC自适应巡航时，在以下哪种情况下应立即退出并改为手动驾驶？",opts:["天气晴朗的高速公路","城市拥堵路段、雨雪天气、弯道密集路段","路面平坦的快速路","白天正常路段"],ans:1,exp:"ACC不应在以下场景使用：城市复杂路况（交通灯、行人、交叉口多）、雨雪雾天气（传感器受限）、弯道密集路段（前车频繁丢失）、施工区（车道不规则）、拥堵跟车时需频繁启停的场景。",tip:"口诀：ACC禁区=城市复杂路/雨雪天/弯多/施工区。ACC是高速神器，不是万能器。"},
{id:435,cat:"smart",type:"choice",q:"自动紧急制动系统（AEB）的功能是什么？",opts:["让车自己开","检测到前方碰撞风险时自动施加制动以避免或减轻碰撞","自动泊车","自动超车"],ans:1,exp:"AEB（Autonomous Emergency Braking）=通过雷达/摄像头检测前方障碍物，当系统判断碰撞风险高（驾驶人未反应）时，先发出警告，如驾驶人仍未采取措施则自动紧急制动。AEB可显著降低追尾事故率。",tip:"口诀：AEB=眼看要撞了，车自己帮你刹车。但别依赖——它只是最后的保险。"},
{id:436,cat:"smart",type:"judgment",q:"智能驾驶辅助系统（ADAS）可以替代驾驶人保持专注，因此在使用ADAS时可以回复手机消息。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"ADAS=辅助≠替代。使用ADAS时驾驶人仍需全程监控路况并随时准备接管。开车玩手机不仅严重违法（记3分/高速公路记9分），即使有ADAS也是极其危险的行为。机器会犯错，人才是最后的安全防线。",tip:"口诀：ADAS再聪明也只是辅助。开车看手机=3分（高速9分）+命在冒险。"},
{id:437,cat:"smart",type:"choice",q:"盲区监测系统（BSD/BSM）提示灯（通常在后视镜上）亮起时，表示什么？",opts:["可以安全变道","相邻车道盲区内有车辆，此时不应变道","车速过快","需要加油"],ans:1,exp:"BSD灯亮=盲区有车/有车快速接近中→禁止变道。BSD通过后角雷达或摄像头监测后视镜视野盲区，在相邻车道有车时点亮警示灯。变道前除了看BSD指示灯，还应回头确认。",tip:"口诀：BSD灯亮=盲区有东西，别变道。灯不亮也要回头看一眼——系统可能漏报。"},
{id:438,cat:"smart",type:"choice",q:"交通标志识别系统（TSR）识别到限速标志后会在仪表盘显示，以下哪项是正确的？",opts:["系统识别的限速永远准确，不用再看路边的标志","系统可能识别错误（如误读匝道限速），驾驶人仍需以实际标志为准","不需要理会","可以超速行驶"],ans:1,exp:"TSR（Traffic Sign Recognition）=通过摄像头读取限速标志显示在仪表盘。但系统可能：误读匝道/辅路限速为主路限速、漏读被遮挡的标志、把货车限速识别为小型车限速等。驾驶人有义务以实际标志为准——TSR只是辅助提醒。",tip:"口诀：TSR识别限速=参考用。路边真标志才是法律依据。TSR把匝道40读成高速40=别信。"},
{id:439,cat:"smart",type:"judgment",q:"自动泊车辅助系统（APA）可以完全自动地将车辆停入任何类型的停车位，驾驶人无需任何操作。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"APA仍需驾驶人保持参与——选择车位类型（垂直/平行/斜列）、在系统操作过程中监控周围环境、随时准备制动停止。不是所有车位APA都能识别（线框不清、空间过小等无法识别）。驾驶人永远是最终责任人。",tip:"口诀：自动泊车≠全自动。你负责选车位+监控+随时刹停。撞了算你的。"},
{id:440,cat:"smart",type:"choice",q:"使用L2级辅助驾驶（含ACC+LKA）时，系统提示「请接管方向盘」，而驾驶人未反应，车辆会怎么做？",opts:["继续自动驾驶","经过多次提醒后系统退出辅助驾驶，车辆逐渐减速并可能自动停车","自动加速","自动变道到路边"],ans:1,exp:"L2系统检测到驾驶人长时间无操作时：①先视觉+声音提醒→②如仍未接管，ACC和LKA相继退出→③车辆可能自行减速（部分车型会逐渐刹停在当前车道并自动呼叫紧急救援）。这是「脱手检测」的安全退级策略。",tip:"口诀：长时间不摸方向盘→系统警告→你不理→系统退出+减速停车。不是不管你，是不敢帮你开了。"},
{id:441,cat:"smart",type:"judgment",q:"智能远光灯系统（IHBC/AHB）可以自动切换远近光灯，在会车和跟车时自动切换为近光。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"IHBC（Intelligent High Beam Control）=通过摄像头检测前方车辆尾灯和对向车头灯，自动在远光和近光之间切换，避免眩目其他车辆。但仍有失灵可能——驾驶人有监督和手动干预的义务。",tip:"口诀：自动远光=会车跟车自动切近光。好用但别全信，该手动就手动。"},
{id:442,cat:"smart",type:"choice",q:"疲劳驾驶监测系统（DMS）通过什么方式检测驾驶人疲劳？",opts:["检测车速","通过车内摄像头监测驾驶人眼睑闭合频率、打哈欠、头部姿态等面部特征","检测油耗","检测胎压"],ans:1,exp:"DMS（Driver Monitoring System）=通过车内红外摄像头实时监测驾驶人面部特征：闭眼时间>2秒、连续打哈欠次数、头部下垂/歪斜频率等。检测到疲劳迹象时发出声音和视觉警告，提醒驾驶人休息。",tip:"口诀：DMS=摄像头看你的脸→闭眼久/打哈欠多/头歪→报警让你休息。DMS说你累了你就真该歇了。"},
{id:443,cat:"smart",type:"judgment",q:"车道偏离预警系统（LDW）在车辆偏离车道时会自动纠正方向，使车辆回到车道中央。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"LDW（Lane Departure Warning）仅提供「警告」（声音/振动/视觉），不会主动干预方向。LKA/LCC（Lane Keeping Assist/Centering）才会主动施加转向力进行纠正。这是两个不同的系统——一个管警告，一个管纠正。",tip:"口诀：LDW=只叫不动（警告你偏了）；LKA=又叫又动（帮你拉回来）。一字之差，功能差大了。"},
{id:444,cat:"smart",type:"choice",q:"关于2026年智能驾驶辅助系统的使用，以下哪项说法正确？",opts:["可以完全依赖系统驾驶","驾驶人始终是车辆的第一责任人，必须监控系统运行并随时准备接管","系统出错时由汽车厂商承担法律责任","使用辅助驾驶时可以双手离开方向盘"],ans:1,exp:"当前法律框架下，驾驶人是车辆操作的法律责任人。即使使用辅助驾驶系统，发生事故的责任仍由驾驶人承担（系统故障可另向厂家追偿，但不影响驾驶人的直接责任）。双手离开方向盘属于危险驾驶行为。",tip:"口诀：出了事故你负责（不是系统负责）。L2辅助=你在开，系统只是帮手。"},
{id:445,cat:"smart",type:"judgment",q:"在雨雪雾等恶劣天气条件下，应谨慎使用或关闭ACC自适应巡航和LKA车道保持等辅助驾驶功能。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"恶劣天气=传感器受限（摄像头被遮挡/雷达信号衰减）→系统识别能力大幅下降或失效→此时使用ADAS可能造成系统误判和错误操作。应关闭辅助驾驶，人工全神关注驾驶。",tip:"口诀：天气差（雨雪雾）→关闭ADAS→手动全神开。传感器看不清的时候别让它帮你开。"},
{id:446,cat:"smart",type:"choice",q:"后方交通穿行预警系统（RCTA）主要在什么场景下发挥作用？",opts:["高速公路行驶","倒车出库时，检测车尾两侧横向穿行的车辆/行人","弯道行驶","隧道行驶"],ans:1,exp:"RCTA（Rear Cross Traffic Alert）=倒车出库或驶出车位时，通过后角雷达探测车尾两侧正在横向穿行的车辆/行人，发出声音和视觉警告。在大型SUV/MPV倒车出库视线受阻时非常实用。",tip:"口诀：RCTA=倒车时帮你看两边有没有来车/来人。倒车出库盲区大，RCTA是你后脑勺的眼睛。"},
{id:447,cat:"smart",type:"judgment",q:"抬头显示系统（HUD）将车速、导航等信息投射在前挡风玻璃上，驾驶人查看信息时无需低头，因此可以安全地长时间注视HUD信息。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"HUD虽减少了低头频率，但长时间注视HUD信息（如阅读导航详情）仍然会使视线离开路面。HUD的设计理念是让驾驶人「扫一眼即可获取信息」，而非「盯着看」。视线离开路面超过2秒就有事故风险。",tip:"口诀：HUD=让你少低头，但别盯着看。扫一眼就回路面，超过2秒就危险。"},
{id:448,cat:"smart",type:"choice",q:"电子稳定程序（ESP/ESC）在车辆出现侧滑趋势时会如何干预？",opts:["没有任何作用","自动对单个或多个车轮施加制动力，并调整发动机输出扭矩，帮助驾驶人恢复车辆稳定","只会报警","让车辆加速"],ans:1,exp:"ESP=通过传感器持续监测车辆实际行驶方向与方向盘指向的差异。一旦检测到转向不足（推头）或转向过度（甩尾），立刻对特定车轮施加制动力+降低发动机扭矩输出，帮助车辆回到正确轨迹。ESP是20世纪最重要的汽车安全发明之一。",tip:"口诀：ESP=要失控时（推头/甩尾）→自动单轮刹车+减动力→拉你回来。ESP灯闪的时候它正在救你。"},
{id:449,cat:"smart",type:"judgment",q:"2026年新规要求汽车厂商在宣传辅助驾驶功能时，不得使用「自动驾驶」「无人驾驶」等误导性用语。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年工信部和市场监管总局联合发文，明确禁止车企在L2/L2+级别辅助驾驶的宣传中使用「自动驾驶」「无人驾驶」「智能驾驶」等可能误导消费者的用语，须明确标注「辅助驾驶，驾驶人全程负责」。",tip:"口诀：2026新规=汽车广告不许吹「自动驾驶」。必须写「辅助驾驶，人负责」。见到「全自动」=虚假宣传。"},
{id:450,cat:"smart",type:"choice",q:"360°全景影像系统（AVM）在泊车时，以下哪项说法正确？",opts:["可以完全依赖AVM来泊车，不需要看后视镜","AVM有盲区和图像畸变，泊车时仍需配合后视镜和直接观察","AVM在所有天气条件下都完美无瑕","AVM可以替代所有的安全观察"],ans:1,exp:"AVM（Around View Monitor）=通过车身四周摄像头合成鸟瞰图。但AVM存在：拼接盲区（四摄像头拼接处）、图像畸变（鱼眼镜头边缘变形）、延迟、低照度时画质下降等限制。泊车时仍需配合物理后视镜和直接观察。",tip:"口诀：360影像=鸟瞰辅助，有盲区+变形。泊车=360+看镜子+回头看，三者结合。"},
{id:451,cat:"smart",type:"judgment",q:"智能驾驶辅助系统的传感器（摄像头、雷达）在冬季可能会被冰雪覆盖而失效，出发前应清理传感器表面。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"冰雪覆盖摄像头和雷达表面=传感器被遮挡=相关ADAS功能失效（系统通常会提示传感器被遮挡）。冬季出发前应检查并清理前挡风玻璃摄像头区域、前后保险杠雷达、后视镜下方摄像头。",tip:"口诀：冬天出门前擦一擦传感器（摄像头+雷达）表面的冰雪。传感器瞎了=辅助驾驶全瞎。"},
{id:452,cat:"smart",type:"choice",q:"以下关于高速公路「车路协同」（V2X）系统的描述，哪项是正确的？",opts:["已经在全国所有高速公路全面应用","车路协同可通过路侧设备向车辆发送前方路况、施工、事故等信息，但目前仅在部分示范路段部署","不需要任何基础设施","车辆可以完全自动驾驶"],ans:1,exp:"V2X（Vehicle-to-Everything）=车与车（V2V）、车与路（V2I）、车与人（V2P）等的信息交互。2026年V2X仅在部分智能高速示范路段和智能城市区域部署，全国大规模覆盖尚需时间。驾驶人不应过度依赖。",tip:"口诀：车路协同=路给车发信息，2026年只在少数试点路段有。你的日常驾驶路段还没覆盖。"},
{id:453,cat:"smart",type:"judgment",q:"DMS（驾驶员监测系统）检测到驾驶人闭眼超过2秒时，系统会发出警报。这是因为疲劳驾驶检测已经采用了新的「行为+生理+轨迹」三维判定标准。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年新规升级疲劳驾驶检测标准为三维判定：行为（闭眼时长、打哈欠频率等）+生理（部分车型有心率监测）+轨迹（车辆行驶轨迹是否异常偏离）。闭眼超2秒、频繁点头打哈欠等均会被系统认定为疲劳驾驶。",tip:"口诀：2026疲劳检测=行为+生理+轨迹三维判定。闭眼2秒就报警。"},
{id:454,cat:"smart",type:"choice",q:"关于智能驾驶辅助系统的OTA升级，以下说法正确的是？",opts:["OTA升级不影响车辆使用","OTA升级应选择车辆停放安全、电量充足、网络稳定时进行，升级过程中车辆可能无法行驶","OTA升级可以在行驶中进行","OTA升级后会改变车辆颜色"],ans:1,exp:"OTA升级=车辆软件远程更新。升级过程中车辆部分或全部系统可能不可用（包括动力系统），一般要求在P挡+电量充足+网络稳定+安全停车状态下进行。升级期间不能驾驶车辆。",tip:"口诀：OTA升级=停好车+P挡+电量足+网好。升级中车没法开。别在路边临时停着升级。"},
{id:455,cat:"smart",type:"choice",q:"以下哪种做法违反了对智能驾驶辅助系统正确使用的原则？",opts:["在使用ACC时保持手握方向盘","在使用LKA时监控路况","开启LKA后双手离开方向盘做其他事情","识别到天气变差后关闭辅助驾驶功能"],ans:2,exp:"双手离开方向盘+做其他事情=严重违反L2辅助驾驶使用原则。即使系统在帮你操控，驾驶人也必须全程参与驾驶任务——手在方向盘上，眼在路面上，随时接管。",tip:"口诀：L2不是脱手许可证。手离方向+做别的事=危险驾驶+违法。永远记住你是司机。"},

// ═══════════════════════════════════════════════════════════════
// 十二、新型交通标志 2026新增 (newsigns) — 20题 (456-475)
// ═══════════════════════════════════════════════════════════════
{id:456,cat:"newsigns",type:"choice",q:"2026年新增的「交通事故管理区」标志的特征是什么？",opts:["黄底三角形","荧光火红色底+黑色边框+「事故」字样","蓝底圆形","白底红圈"],ans:1,exp:"2026年新增「交通事故管理区」标志：荧光火红色底色+黑色边框+「事故」白色字样。用于交通事故现场前方，警示驾驶人进入事故管理区域，须减速慢行、服从现场指挥。",tip:"口诀：新标志=荧光火红底+黑框+「事故」二字。看到这个=前方有事故现场，减速听指挥。"},
{id:457,cat:"newsigns",type:"judgment",q:"2026年新增的「充电站预告」标志采用绿色底+充电插头图案，用于高速公路预告前方服务区设有充电设施。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速公路指路标志新增充电站预告标志：绿底白色充电插头图案+距离提示。设于设有充电站的服务区前2km、1km、500m及入口处，方便新能源车主提前规划。",tip:"口诀：绿底+充电插头=前方服务区有充电站。2km→1km→500m→入口逐级提醒。"},
{id:458,cat:"newsigns",type:"choice",q:"2026年新增的「应急避难所」交通标志的背景颜色与图案是什么？",opts:["黄底+帐篷图案","橙底+白色人形和箭头+避难所图案","蓝底+白色图案","绿底+白色图案"],ans:1,exp:"「应急避难所」标志=橙色底+白色图案，指示前方设有地震、洪水等自然灾害时的临时应急避难场所及方向。属于新型公共安全交通标志。",tip:"口诀：橙底+人形箭头=应急避难所方向。自然灾害时的逃生指引标志。"},
{id:459,cat:"newsigns",type:"judgment",q:"2026年新增要求高速公路隧道入口处设置「智能调光区」预告标志，提醒驾驶人前方隧道入口有灯光强度自动渐变调节。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"新建和改建高速公路隧道入口设置智能调光区（过渡照明），解决黑洞效应。隧道入口前设预告标志，提醒驾驶人隧道内灯光可自动调节亮度以适应外部光线变化。",tip:"口诀：新隧道=智能调光+预告标志。进隧道时灯光自适应过渡，不用自己调灯。"},
{id:460,cat:"newsigns",type:"choice",q:"「动态限速标志」（可变限速电子屏）在高速公路的主要作用是什么？",opts:["固定限速","根据实时交通、天气和路况动态调整限速值","只显示广告","显示时间"],ans:1,exp:"动态限速标志通过LED显示屏实时调整限速值（如大雾时降为60km/h）。2026年更多高速公路部署了此类智能交通设施，驾驶人应按动态标志显示的限速行驶。显示限速与固定标志不一致时以动态限速为准。",tip:"口诀：电子屏限速=实时变化（天不好就降速）。动态限速>固定标志。显示屏上什么速度就什么速度。"},
{id:461,cat:"newsigns",type:"choice",q:"2026年新增的「非机动车等待区」路面标线颜色是什么？",opts:["白色","黄色","绿色+自行车图案","蓝色"],ans:2,exp:"「非机动车等待区」=路口停止线前用绿色铺装+白色自行车图案标识的非机动车专用等待区域。机动车不得驶入或占用该区域。设于非机动车流量大的城市路口。",tip:"口诀：路口绿色区域+自行车图案=非机动车等待区。机动车别压进去！"},
{id:462,cat:"newsigns",type:"judgment",q:"2026年新增标准规定，「公交专用道」标志增加时段标注，在非专用时段社会车辆可以驶入。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年标志更新：公交专用道标志更加清晰地标注专用时段（如「7:00-9:00，17:00-19:00」），非专用时段社会车辆可正常使用该车道。全天候公交专用道仍保持24小时禁止社会车辆驶入。",tip:"口诀：公交专用道看时段。标了时间的=非高峰社会车能走；没标时间=24小时公交车专属。"},
{id:463,cat:"newsigns",type:"choice",q:"「电动汽车充电车位」标志的底色和图案是什么？",opts:["黄底+加油机","蓝底/绿底+白色充电插头图案+车位线","红底+叉","白底+黑字"],ans:1,exp:"充电车位标志=蓝底或绿底方形+白色充电插头图案，配合绿色车位标线。该车位仅供新能源汽车充电使用（部分有时长限制），燃油车占用将被处罚。",tip:"口诀：绿底/蓝底+充电插头=充电专用车位。油车停进去=违法+被电车车主白眼。"},
{id:464,cat:"newsigns",type:"judgment",q:"2026年「人行横道」预告标线新增了三维立体视觉效果（3D斑马线），使标线看起来像悬浮在空中，增强视觉冲击力提醒驾驶人减速。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年在部分城市试点3D立体人行横道标线——通过色彩的明暗变化营造悬浮的立体视觉效果，开车靠近时会产生「前面有障碍物」的视觉错觉，促使驾驶人提前减速。属于创新交通安全设施。",tip:"口诀：3D斑马线=看起来像悬浮白柱子→吓一跳→减速。假立体真减速，对老司机特别有效。"},
{id:465,cat:"newsigns",type:"choice",q:"「注意自动驾驶测试车辆」警告标志（2026新增）的颜色和图案是什么？",opts:["黄底黑图案三角形","蓝底白图案圆形","荧光黄绿色底+黑色车辆和传感器图标","红底白字"],ans:2,exp:"2026年新增警告标志：荧光黄绿色底+黑色车辆和传感器波纹图案。设于自动驾驶测试路段前方，提醒过往车辆注意测试车辆（可能有异常驾驶行为），保持安全距离。",tip:"口诀：荧光黄绿底+带传感器的车=前方有自动驾驶测试车。它们可能操作不按常理，保持距离。"},
{id:466,cat:"newsigns",type:"choice",q:"2026年新增「电动自行车专用道」标志与普通非机动车道标志的区别是什么？",opts:["没有区别","电动自行车专用道标志使用蓝底+电动自行车轮廓图案，与非机动车道（自行车图案）不同","只用文字标注","没有这样的标志"],ans:1,exp:"2026年新标准区分了「非机动车道」（自行车图案）」和「电动自行车专用道」（电动自行车轮廓图案）。电动自行车应按标志行驶在专用车道内，不得驶入机动车道或普通非机动车道（混合通行时除外）。",tip:"口诀：新标志=电动自行车有专用道（不一样于自行车道）。蓝底+电动车轮廓=电动自行车专属。"},
{id:467,cat:"newsigns",type:"judgment",q:"「预约通行区」标志（2026新增）表示前方区域需通过APP提前预约方可驶入。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年部分城市拥堵区域和景区试行预约通行制，新增「预约通行区」标志——蓝底白字+二维码图案。驾驶人需通过交管12123或城市交通APP提前预约方可驶入。未预约驶入属于违反禁令标志（记1分）。",tip:"口诀：蓝底+二维码=预约通行区。提前在APP预约才能进，没预约=闯禁行（记1分）。"},
{id:468,cat:"newsigns",type:"choice",q:"新型「路侧智能感知区」标志提示的是什么？",opts:["前方有加油站","前方路段设有路侧智能感知设备（雷达/摄像头），可实时监测交通状况","前方有限速摄像头","前方有ETC"],ans:1,exp:"「路侧智能感知区」=前方路段部署了路侧感知设备（激光雷达、毫米波雷达、高清摄像头等），用于车路协同和智慧交通管理。驾驶人应注意按标志和信号行驶，该区域交通违规被自动记录的概率较高。",tip:"口诀：路侧智能感知区=你的开车行为正在被全方位感知中。老实按规矩开。"},
{id:469,cat:"newsigns",type:"judgment",q:"「可变车道」（潮汐车道）标志在2026年增加了LED指示灯，根据不同时段显示不同行驶方向。进入可变车道前必须查看指示灯显示的当前允许行车方向。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年可变车道标志升级为LED动态显示+固定标志组合。进入前必须看上方LED箭头指示（←直行/↑直行/↗右转等），在不同时段方向可能完全相反。看错方向=逆向行驶或违反导向车道。",tip:"口诀：潮汐车道（锯齿线）=进去前抬头看LED箭头。早上往东晚上往西，不看就逆行。"},
{id:470,cat:"newsigns",type:"choice",q:"2026年新增的「无障碍停车位」标志兼有什么特征？",opts:["普通蓝底P","蓝底P+轮椅图案，且车位宽度大于普通车位","只有轮椅图案","黄底P"],ans:1,exp:"无障碍停车位标志=蓝底P+轮椅图案，地面标线为黄色+轮椅标志。车位宽度通常≥3.7米（比普通2.5米宽），有下车过渡区。仅供残疾人车辆停放，非残疾人车辆占用将受重罚。",tip:"口诀：蓝P+轮椅+宽车位=无障碍专用车位。不是残疾人别停，停了重罚。"},
{id:471,cat:"newsigns",type:"judgment",q:"2026年新增「应急医疗直升机停机坪」交通指示标志，用于指示高速公路附近设有医疗直升机起降点。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年部分高速公路服务区和重点路段增设医疗直升机停机坪+配套指示标志（白底红十字+直升机图案），用于重伤员空中转运。是高速公路应急救援体系升级的一部分。",tip:"口诀：白底红十字+直升机=医疗直升机停机坪。高速重伤员空中转运通道。"},
{id:472,cat:"newsigns",type:"choice",q:"关于「禁鸣喇叭」标志的2026年更新，以下哪项正确？",opts:["保持不变","部分城市更新增加了电子警察抓拍提示，违规鸣喇叭将被声呐定位抓拍并罚款","该标志被取消","全国统一取消了禁鸣规定"],ans:1,exp:"2026年更多城市部署了声呐定位电子警察（声阵列雷达），精准定位违规鸣喇叭车辆。禁鸣区域鸣喇叭将被自动抓拍取证，处以罚款。禁鸣标志增加了「电子抓拍」辅助文字。",tip:"口诀：禁鸣标志+电子抓拍=别按喇叭。声呐定位能精确到哪辆车按的喇叭——跑不掉。"},
{id:473,cat:"newsigns",type:"judgment",q:"2026年「限速标志」新增了「建议速度」的区分——黄底黑字数字为建议速度，红圈黑字为法定最高限速。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"建议速度标志=黄底（或橙底）黑字方形，为非强制性建议；法定限速=红圈白底黑字圆形，为强制性规定。建议速度可以结合路况自行判断是否采纳，法定限速必须遵守。",tip:"口诀：黄底数字=建议速度（你看着办）；红圈数字=最高限速（必须遵守）。黄色是温柔的提醒，红色是法律的底线。"},
{id:474,cat:"newsigns",type:"choice",q:"2026年新增「反向弯路+连续弯道长度预告」组合标志，预告内容包含什么？",opts:["只有弯道方向","弯道方向+弯道长度（如500m）+建议速度","只显示速度","只有长度"],ans:1,exp:"新型弯道预告标志=弯道方向图形+连续弯道总长度（如2km）+弯道个数+建议速度。帮助驾驶人全面预判前方弯道路段的长度和难度，提前做好驾驶准备。",tip:"口诀：新弯道标志=弯怎么拐+多长+几个弯+建议多快。信息量大了，安全也多了一分。"},
{id:475,cat:"newsigns",type:"judgment",q:"2026年新增标准规定，学校区域限速标志应配备「注意儿童」辅助标志和地面「慢」字标记，三者形成完整的学校区域交通管控系统。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2026年学校区域安全升级=限速标志（30km/h）+「注意儿童」警告标志+路面黄色「慢」字标记+彩色防滑路面（红色或绿色提示区）。四重保障构成学校区域交通安全系统。",tip:"口诀：学校区=限速30+注意儿童+路面「慢」字+彩色路面。四重保险护孩子安全。"},

// ═══════════════════════════════════════════════════════════════
// 综合补充题 (supplementary) — 25题 (476-500)
// ═══════════════════════════════════════════════════════════════
{id:476,cat:"laws",type:"choice",q:"机动车所有人将机动车作为抵押物抵押的，应当向登记地车辆管理所申请什么登记？",opts:["注册登记","转移登记","抵押登记","注销登记"],ans:2,exp:"机动车作为抵押物时，应向登记地车辆管理所申请抵押登记。抵押权消灭时应申请解除抵押登记。",tip:"口诀：车抵押了=办抵押登记。还清贷款=办解除抵押登记。"},
{id:477,cat:"signals",type:"judgment",q:"在没有非机动车道的道路上，非机动车应靠车行道的右侧行驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无非机动车道时，非机动车应靠车行道右侧行驶（距右侧边缘不超过1.5米）。机动车应与非机动车保持安全横向距离。",tip:"口诀：没有非机动车道=非机动车靠右边1.5米内行驶。机动车从左边过，保持距离。"},
{id:478,cat:"safe",type:"choice",q:"夜间驾驶机动车在窄路、窄桥与非机动车会车时，以下做法正确的是？",opts:["使用远光灯","使用近光灯","关闭灯光","连续闪灯驱赶"],ans:1,exp:"窄路窄桥+非机动车=必须用近光灯。远光会使骑车人因眩目而无法看清路面，可能骑车摔倒，极其危险。",tip:"口诀：窄路遇上骑车人=近光灯（别闪远光）。你一晃他倒了就是你的责任。"},
{id:479,cat:"points",type:"judgment",q:"2026年实施的交通违法记分体系中保留了2分档。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"2022年4月1日起记分体系已取消2分档，调整为12/9/6/3/1五档。2026年继续执行此体系。任何提及2分记分的说法都是错误的。",tip:"口诀：记住——2022年起就没有2分档了！12/9/6/3/1是现行五档。"},
{id:480,cat:"points",type:"choice",q:"以下哪种情形不会导致驾驶证被吊销？",opts:["醉酒驾驶机动车","饮酒后驾驶机动车被处罚再次饮酒驾驶","驾驶拼装机动车上路","一个记分周期内记满12分"],ans:3,exp:"记满12分=扣留驾驶证+参加学习考试，不是吊销。吊销的情形包括：醉酒驾车、二次酒驾、驾驶报废车/拼装车、发生重大交通事故构成犯罪等。扣留是暂时的，吊销是永久的。",tip:"口诀：12分=扣留（暂时的）；醉驾/二次酒驾=吊销（永久的）。扣留≠吊销。"},
{id:481,cat:"highway",type:"judgment",q:"设计最高时速低于70公里的机动车不得进入高速公路。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"设计最高时速低于70km/h的机动车（如低速电动车、拖拉机、部分摩托车等）不得进入高速公路。高速公路最低限速60km/h，车速过低的车辆无法安全融入车流。",tip:"口诀：车速跑不到70码的车不能上高速。高速有门槛，太慢不行。"},
{id:482,cat:"weather",type:"judgment",q:"夜间在道路上发生车辆故障难以移动时，应开启危险报警闪光灯、示廓灯和后位灯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"夜间故障难以移动=双闪+示廓灯+后位灯+来车方向设警告标志。四重警示确保后方来车能及时发现。",tip:"口诀：夜间抛锚=多灯齐亮（双闪+示廓+后位）+警示牌。让自己变成一个发光的警示柱。"},
{id:483,cat:"emergency",type:"choice",q:"救助失血过多导致休克的伤员时，应采取什么体位？",opts:["坐位","平卧位，下肢抬高20-30°，头偏向一侧","站位","俯卧位"],ans:1,exp:"失血性休克=平卧+下肢抬高20-30°（促进下肢血液回流）+头偏一侧（防呕吐窒息）+保暖。这是标准的休克急救体位。",tip:"口诀：休克=平躺+抬腿30度+保暖。把腿抬高=把腿里的血赶回心脏和大脑。"},
{id:484,cat:"ev",type:"judgment",q:"纯电动汽车的电池组通常安装在车辆底部（底盘位置），这降低了车辆重心，使车辆更稳定。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"电池组置于底盘=重心低→车辆侧翻风险降低。但电池组在底盘也有风险——底盘磕碰可能导致电池组损坏甚至起火。过减速带和坑洼路面应减速慢行。",tip:"口诀：电池在底盘=重心低=稳（不容易翻）。但怕磕底盘，过减速带要慢。"},
{id:485,cat:"smart",type:"judgment",q:"APA自动泊车系统可以识别并停入任何类型和尺寸的停车位。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"APA并非万能——需要标准标线清晰的车位、空间足够（通常要求大于车长+0.8米以上）、不规则车位（斜列、无标线等）可能无法识别。驾驶人是最终责任人。",tip:"口诀：自动泊车挑车位——要标线清楚+空间够大。小位置它不行的。"},
{id:486,cat:"newsigns",type:"judgment",q:"2026年起，全国高速公路服务区全面配备新能源充电设施，并在服务区入口前方设置充电站预告标志。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"2026年高速服务区充电设施覆盖率显著提高，但尚未达到「全国每个服务区都有」。部分偏远地区服务区仍可能无充电设施。出发前应使用充电APP查询沿途充电站分布。",tip:"口诀：高速充电站越来越多但非全覆盖。出远门前用充电APP规划路线，别想当然。"},
{id:487,cat:"laws",type:"choice",q:"以下哪种车辆不属于特种车辆？",opts:["警车","消防车","救护车","出租车"],ans:3,exp:"特种车辆=警车、消防车、救护车、工程救险车，使用警报器和标志灯具时可不受行驶路线、方向、速度和信号灯的限制。出租车不属于特种车辆，无特权。",tip:"口诀：特种车=警+消+救+工程救险。出租车=普通车，没特权。"},
{id:488,cat:"signals",type:"judgment",q:"当车道上有「菱形◇」标线时，表示前方有减速让行线。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"菱形◇标线=人行横道预告标线（不是减速让行线），提示前方30-50米有人行横道。减速让行线是路口的白色双虚线。",tip:"口诀：◇菱形=前方人行横道预告（30-50米后有斑马线）。减速让行线=路口白色双虚线。"},
{id:489,cat:"safe",type:"choice",q:"雨天驾驶时，大型车辆驶过溅起的水雾会影响后车视线，正确的做法是？",opts:["紧跟大型车辆","与大型车辆保持更远的距离，必要时开启雨刮器最高档和近光灯","加速超过大车","鸣喇叭警告大车"],ans:1,exp:"大车溅起的水雾严重影响后车视线，应主动拉大跟车距离+开近光灯（增加自身可见度）+雨刮开到合适挡位+必要时在安全条件下超越大车。",tip:"口诀：雨天跟大车=远点+近光灯+雨刮快档。大车溅水雾=瞬间视野归零，保持距离。"},
{id:490,cat:"points",type:"choice",q:"以下哪项不属于2026年记12分的违法行为？",opts:["醉酒驾车","使用伪造号牌","高速公路上倒车","驾驶时拨打手机"],ans:3,exp:"驾驶时拨打手机=普通路3分/高速9分（不是12分）。醉酒驾车、伪造号牌、高速倒车均为12分。",tip:"口诀：打电话不是12分！（普通3分，高速9分）。别把打电话和那些最严重的混淆。"},
{id:491,cat:"highway",type:"judgment",q:"进入高速公路的匝道后，应将车速迅速提高到60km/h以上。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"匝道限速通常为40km/h，进入加速车道后才应将车速提高到60km/h以上再并入主线。在匝道内就提速到60km/h以上是危险的——匝道弯道半径小，速度过快容易失控。",tip:"口诀：匝道=40码慢慢走（弯多）；加速车道=60码+再并主线。别在匝道里飙。"},
{id:492,cat:"weather",type:"choice",q:"在高温天气下，以下哪项做法是正确的？",opts:["长时间怠速开空调","不要在车内放置打火机、碳酸饮料、充电宝等易爆物品","将宠物单独留在车内开空调","轮胎胎压调低防爆胎"],ans:1,exp:"夏季高温车内温度可升至70℃以上，打火机（爆炸）、碳酸饮料罐（炸裂）、充电宝（电池膨胀起火）等均为危险品。宠物和儿童绝对不可单独留在车内（即使开空调也可能因系统故障导致中暑死亡）。",tip:"口诀：夏天车内=烤箱。打火机/可乐罐/充电宝=车内定时炸弹。别把孩子/宠物锁车里。"},
{id:493,cat:"emergency",type:"judgment",q:"如果驾驶人在行车中突发疾病无法继续驾驶，可以开启自动驾驶功能让车辆自动行驶到安全地点。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"截至2026年没有车辆具备这种能力。L2辅助驾驶无法在驾驶人完全失能的情况下安全驾驶——系统会在检测到无操作后退出并减速停车（停在当前车道，可能不是安全地点）。突发疾病应尽最大努力安全停车并拨打120。",tip:"口诀：人不行了车不会自己开到安全区。它只会停在当前车道。身体不适赶紧提前靠边停。"},
{id:494,cat:"ev",type:"judgment",q:"插电式混合动力汽车（PHEV）同时具有燃油发动机和电动机，在电池电量耗尽后仍可依靠燃油继续行驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"PHEV=有电用电、没电用油，没有纯电车的续航焦虑。但电池亏电后油耗会高于同款非插电混动车型（因为多了电池重量）。日常应多用电驱动以省钱环保。",tip:"口诀：PHEV=双保险——有电是电车，没电是油车。但没电油耗高，所以常充电。别当油车开。"},
{id:495,cat:"smart",type:"choice",q:"前方碰撞预警系统（FCW）在检测到碰撞风险时首先会做什么？",opts:["自动刹车","发出视觉和声音警告提醒驾驶人采取措施","自动变道","自动加速"],ans:1,exp:"FCW（Forward Collision Warning）=先用声音+视觉（仪表盘/挡风玻璃投影红色警示）提醒驾驶人。如驾驶人未采取措施，AEB再自动制动。FCW管警告，AEB管制动——两个系统配合工作。",tip:"口诀：FCW=先叫你（报警）→不听→AEB帮你刹车。FCW是闹钟，AEB是自动刹车。"},
{id:496,cat:"newsigns",type:"choice",q:"「禁止电动自行车驶入」标志区别于「禁止非机动车」标志的特征是什么？",opts:["完全一样","红圈白底+电动自行车轮廓图案（区别于自行车轮廓）","只有文字","没有这样的标志"],ans:1,exp:"2026年新标准区分了「禁止非机动车」（自行车图案）和「禁止电动自行车」（电动自行车轮廓图案）。管理精细化——部分路段可能仅禁电动自行车，允许普通自行车通行。",tip:"口诀：红圈+电动车轮廓=禁电动车（不禁普通自行车）。看图案区分，电动车有电池轮廓。"},
{id:497,cat:"laws",type:"judgment",q:"驾驶机动车运载超大型机械设备等不可解体物品时，应经公安机关交通管理部门批准，按指定时间、路线、速度行驶并悬挂明显标志。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"超限不可解体物品运输须取得「超限运输车辆通行证」，按审批的时间、路线、速度行驶，并悬挂明显超限标志。夜间行驶还需开启相应灯光。",tip:"口诀：大件运输=先审批→按指定路线走→挂标志。不是你想运就能运的。"},
{id:498,cat:"points",type:"choice",q:"2026年关于学法减分的正确描述是？",opts:["可以无限制减分","一个记分周期最多减免6分，可通过网上学习考试或参加公益活动","只能通过线下学习","每个记分周期可以减免12分"],ans:1,exp:"学法减分=网上学习考试（30分钟+20题答对18题=减1分）或线下公益活动=一个周期最多减6分。不能跨周期使用。",tip:"口诀：学法减分6分封顶，网上学半小时+考试通过=减1分。一年最多6次。"},
{id:499,cat:"highway",type:"judgment",q:"车辆在高速公路行驶中，车速超过100km/h时突然遇到强侧风，应立即紧急制动减速。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速+强侧风+急刹=极易失控。正确做法：握紧方向盘+松油门缓慢减速+轻微修正方向抵抗侧风。急刹车会使车辆在减速过程中失去横向稳定性。",tip:"口诀：高速遇侧风=握紧方向+松油门慢慢慢下来。急刹=侧风+刹车力=失控。"},
{id:500,cat:"ev",type:"choice",q:"下列关于2026年新能源汽车的表述，哪项是正确的？",opts:["增程式电动车只能纯电行驶","换电模式（换电站）可以在几分钟内完成电池更换，是充电的补充方式","氢燃料电池车排放二氧化碳","纯电动车可以在任何加油站加油"],ans:1,exp:"换电模式=将电量耗尽的电池更换为满电电池，整个过程3-5分钟，是长途出行的有效补能方式。2026年换电站网络正在扩展中。增程式电动车有发动机发电（可加油），氢燃料电池车排放物只有水。",tip:"口诀：换电=3分钟满血复活（换电站换电池）。充电+换电=电车两大补能方式。"}
);
